import { createClient } from '@supabase/supabase-js';
import * as dotenv from 'dotenv';
import { resolve } from 'path';

// Load environment variables from .env.local
dotenv.config({ path: resolve(process.cwd(), '.env.local') });

const supabaseUrl = process.env.VITE_SUPABASE_URL || '';
const supabaseKey = process.env.VITE_SUPABASE_ANON_KEY || '';

if (!supabaseUrl || !supabaseKey) {
  console.error("Faltan las variables de entorno de Supabase.");
  process.exit(1);
}

const supabase = createClient(supabaseUrl, supabaseKey);

async function calculateTotalVersus() {
  try {
    // 1. Obtener todas las categorías admitidas para "ai_curated_pairs"
    const { data: categories, error: catError } = await supabase
      .from('categories')
      .select('id, name, slug, active, generation_mode')
      .eq('active', true)
      .eq('generation_mode', 'ai_curated_pairs');

    if (catError) throw catError;

    if (!categories || categories.length === 0) {
      console.log("No hay categorías activas con generation_mode 'ai_curated_pairs'.");
      return;
    }

    let totalCombinations = 0;
    const categoryStats = [];

    // 2. Para cada categoría, contar cuántas entidades válidas (brands) existen
    for (const category of categories) {
      // Intentar coincidencia con slug
      const { data: entitiesBySlug, error: slugError } = await supabase
        .from('entities')
        .select('id')
        .eq('type', 'brand')
        .ilike('category', category.slug);

      let count = entitiesBySlug?.length || 0;

      // Si no hay con slug, intentar coincidencia con name (mismo fallback que el versus-bot)
      if (count === 0) {
        const { data: entitiesByName, error: nameError } = await supabase
          .from('entities')
          .select('id')
          .eq('type', 'brand')
          .ilike('category', category.name);

        count = entitiesByName?.length || 0;
      }

      // Calcular combinaciones n * (n - 1) / 2
      let combinations = 0;
      if (count >= 2) {
        combinations = (count * (count - 1)) / 2;
      }

      totalCombinations += combinations;

      categoryStats.push({
        name: category.name,
        slug: category.slug,
        entitiesCount: count,
        possibleVersus: combinations
      });
    }

    console.log("=========================================");
    console.log("REPORTE DE POSIBLES BATALLAS VERSUS (IA)");
    console.log("=========================================\n");

    categoryStats.sort((a, b) => b.possibleVersus - a.possibleVersus).forEach(stat => {
      console.log(`Categoría: ${stat.name} (${stat.slug})`);
      console.log(`  - Entidades (marcas): ${stat.entitiesCount}`);
      console.log(`  - Versus posibles:   ${stat.possibleVersus}`);
      console.log("-----------------------------------------");
    });

    console.log(`\n=> VERSUS TOTALES POSIBLES: ${totalCombinations}`);
    console.log(`(Asumiendo batallas sin duplicados: Marca A vs Marca B)`);

  } catch (error) {
    console.error("Error calculando los versus:", error);
  }
}

calculateTotalVersus();

import fs from 'fs';
import path from 'path';
import xlsx from 'xlsx';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const EXCEL_PATH = path.join(__dirname, '../../Catalogo Madre/Catalogo Categorias - Final .xlsx');
const OUT_DIR = path.join(__dirname, '../docs/catalog');
const SEEDS_DIR = path.join(__dirname, '../supabase/seeds');

// Ensure dirs exist
if (!fs.existsSync(OUT_DIR)) fs.mkdirSync(OUT_DIR, { recursive: true });
if (!fs.existsSync(SEEDS_DIR)) fs.mkdirSync(SEEDS_DIR, { recursive: true });

function toSlug(str: string): string {
    if (!str) return '';
    return str.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
}

function normalizeEntityName(name: string): string {
    if (!name) return '';
    let n = name.toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
    n = n.replace(/[^A-Z0-9 ]/g, '');
    return n.trim().replace(/\s+/g, ' ');
}

function cleanDomain(domain: string): string | null {
    if (!domain || typeof domain !== 'string') return null;
    let d = domain.trim().toLowerCase();
    d = d.replace(/^https?:\/\//, '').replace(/^www\./, '');
    d = d.split('/')[0];
    if (d.includes(' ') || d.includes(',')) return null;
    if (d.endsWith('.cl') || d.endsWith('.com') || d.endsWith('.net') || d.endsWith('.org')) {
        return d;
    }
    return null; // For safety, only obvious domains
}

function escapeSql(str: string | null): string {
    if (str === null) return 'NULL';
    return "'" + str.replace(/'/g, "''") + "'";
}

function escapeCsv(str: string | null): string {
    if (str === null) return '';
    const s = String(str);
    if (s.includes(',') || s.includes('"') || s.includes('\n')) {
        return '"' + s.replace(/"/g, '""') + '"';
    }
    return s;
}

function run() {
    console.log(`Reading Excel: ${EXCEL_PATH}`);
    const workbook = xlsx.readFile(EXCEL_PATH);
    const sheetName = workbook.SheetNames[0];
    const sheet = workbook.Sheets[sheetName];
    const rows = xlsx.utils.sheet_to_json<any>(sheet, { header: 1 });

    const headers = rows[0] as string[];
    const dataRows = rows.slice(1).filter(r => r.length > 0 && r[0]);

    const curatedRows: any[] = [];

    // Stats
    const stats = {
        totalRows: dataRows.length,
        curated: 0,
        domainsRespected: 0,
        domainsAutoCompleted: 0,
        domainsEmptyLowConfidence: 0,
        duplicatesConsolidated: 0,
        needsReview: 0,
        entityTypeDistribution: {} as Record<string, number>,
        categoryDistribution: {} as Record<string, number>
    };

    const seenKeys = new Map<string, any>();

    for (let i = 0; i < dataRows.length; i++) {
        const row = dataRows[i];
        const rawCategory = row[0] || '';
        const rawSubcategory = row[1] || '';
        const rawName = row[2] || '';
        const rawDomain = row[3] || '';

        const category = String(rawCategory).trim();
        const subcategory = String(rawSubcategory).trim();
        let entity_name = String(rawName).trim();

        if (!entity_name) continue;

        // Clean trailing spaces and normalize common errors
        entity_name = entity_name.replace(/\s+/g, ' ');

        const entity_slug = toSlug(entity_name);
        const normalized_name = normalizeEntityName(entity_name);

        let entity_type = 'BRAND';

        // Example overrides if evident based on category
        const catLower = category.toLowerCase();
        if (catLower.includes('gobierno') || catLower.includes('institucion') || catLower.includes('municipal')) {
            entity_type = 'INSTITUTION';
        }

        stats.entityTypeDistribution[entity_type] = (stats.entityTypeDistribution[entity_type] || 0) + 1;
        stats.categoryDistribution[category] = (stats.categoryDistribution[category] || 0) + 1;

        const canonical_code = `${entity_type}_${normalized_name.replace(/ /g, '_')}`;

        const extractedDomain = cleanDomain(rawDomain);
        const domain = extractedDomain;

        if (rawDomain && extractedDomain) {
            stats.domainsRespected++;
        } else if (rawDomain && !extractedDomain) {
            stats.domainsEmptyLowConfidence++;
        } else {
            stats.domainsEmptyLowConfidence++;
        }

        const country_code = domain?.endsWith('.cl') ? 'CL' : null;

        let curation_status = 'curated';
        let notes = '';

        const dedupKey = `${category}_${subcategory}_${normalized_name}`;

        if (seenKeys.has(dedupKey)) {
            stats.duplicatesConsolidated++;
            notes = 'Consolidated duplicate from Excel. ';
            continue; // Skip duplicate entirely
        }

        if (rawDomain && !extractedDomain) {
            curation_status = 'needs_review';
            notes += 'Domain review needed. ';
            stats.needsReview++;
        }

        const curatedRecord = {
            category,
            subcategory,
            entity_name,
            entity_slug,
            entity_type,
            domain,
            normalized_name,
            canonical_code,
            country_code,
            primary_category: category,
            primary_subcategory: subcategory,
            source_row_label: `Excel Row ${i+2}`,
            curation_status,
            notes: notes.trim()
        };

        seenKeys.set(dedupKey, curatedRecord);
        curatedRows.push(curatedRecord);
        stats.curated++;
    }

    // 1. Write master-entity-catalog-curated.csv
    const curatedCsvHeaders = ['category', 'subcategory', 'entity_name', 'entity_slug', 'entity_type', 'domain', 'normalized_name', 'canonical_code', 'country_code', 'primary_category', 'primary_subcategory', 'source_row_label', 'curation_status', 'notes'];
    let curatedCsvContent = curatedCsvHeaders.join(',') + '\n';
    curatedRows.forEach(r => {
        curatedCsvContent += curatedCsvHeaders.map(h => escapeCsv(r[h])).join(',') + '\n';
    });
    fs.writeFileSync(path.join(OUT_DIR, 'master-entity-catalog-curated.csv'), curatedCsvContent);

    // 2. Write seed SQL for entities
    let sqlContent = `-- Seed master entities from curated catalog Excel\n`;
    sqlContent += `-- Generated: ${new Date().toISOString()}\n\n`;

    curatedRows.forEach(r => {
        const typeIdQuery = `(SELECT id FROM public.entity_types WHERE slug = '${r.entity_type.toLowerCase()}')`;

        const metadata = {
            original_category: r.category,
            original_subcategory: r.subcategory,
            original_domain: r.domain,
            catalog_source: 'excel',
            curation_status: r.curation_status,
            notes: r.notes
        };

        sqlContent += `INSERT INTO public.signal_entities (entity_type_id, slug, display_name, normalized_name, canonical_code, country_code, primary_category, primary_subcategory, metadata) VALUES (\n`;
        sqlContent += `  ${typeIdQuery},\n`;
        sqlContent += `  ${escapeSql(r.entity_slug)},\n`;
        sqlContent += `  ${escapeSql(r.entity_name)},\n`;
        sqlContent += `  ${escapeSql(r.normalized_name)},\n`;
        sqlContent += `  ${escapeSql(r.canonical_code)},\n`;
        sqlContent += `  ${escapeSql(r.country_code)},\n`;
        sqlContent += `  ${escapeSql(r.primary_category)},\n`;
        sqlContent += `  ${escapeSql(r.primary_subcategory)},\n`;
        sqlContent += `  '${JSON.stringify(metadata).replace(/'/g, "''")}'::jsonb\n`;
        sqlContent += `) ON CONFLICT (canonical_code) DO NOTHING;\n\n`;
    });
    fs.writeFileSync(path.join(SEEDS_DIR, 'master_entities_from_catalog.sql'), sqlContent);

    // 3. Write alias sql draft (optional, minimal for now if useful)
    let aliasSql = `-- Master entity aliases (opcional)\n-- ON CONFLICT ignore to be safe\n\n`;
    aliasSql += `-- Example: Some names might have useful aliases\n`;
    aliasSql += `/* \nINSERT INTO public.entity_aliases (entity_id, alias_name, alias_normalized, confidence_score) \n`;
    aliasSql += `SELECT id, 'Short Name', 'SHORT NAME', 1.0 FROM public.signal_entities WHERE canonical_code = 'BRAND_LONG_NAME' ON CONFLICT DO NOTHING;\n*/\n`;
    fs.writeFileSync(path.join(SEEDS_DIR, 'master_entity_aliases_from_catalog.sql'), aliasSql);

    // 4. Write mapping draft
    const mappingCsvHeaders = ['source_table', 'source_id', 'source_label', 'matched_canonical_code', 'matched_entity_name', 'mapping_status', 'confidence_score', 'notes'];
    let mappingCsv = mappingCsvHeaders.join(',') + '\n';
    curatedRows.forEach(r => {
        const mr = {
            source_table: 'opciones (legacy)',
            source_id: 'unknown_yet',
            source_label: r.entity_name,
            matched_canonical_code: r.canonical_code,
            matched_entity_name: r.entity_name,
            mapping_status: 'predicted',
            confidence_score: '1.0',
            notes: 'Exact match from Excel generation'
        };
        mappingCsv += mappingCsvHeaders.map(h => escapeCsv((mr as any)[h])).join(',') + '\n';
    });
    fs.writeFileSync(path.join(OUT_DIR, 'legacy-to-master-mapping-draft.csv'), mappingCsv);

    // 5. Write Summary
    let summaryMd = `# Catalog Curation Summary\n\n`;
    summaryMd += `- **Total de filas analizadas:** ${stats.totalRows}\n`;
    summaryMd += `- **Total de registros curados:** ${stats.curated}\n`;
    summaryMd += `- **Total de dominios respetados:** ${stats.domainsRespected}\n`;
    summaryMd += `- **Total de dominios autocompletados:** ${stats.domainsAutoCompleted}\n`;
    summaryMd += `- **Total de dominios vacíos por baja confianza:** ${stats.domainsEmptyLowConfidence}\n`;
    summaryMd += `- **Total de duplicados consolidados:** ${stats.duplicatesConsolidated}\n`;
    summaryMd += `- **Total de registros needs_review:** ${stats.needsReview}\n`;

    summaryMd += `\n## Distribución por Entity Type\n`;
    for (const [k, v] of Object.entries(stats.entityTypeDistribution)) {
        summaryMd += `- ${k}: ${v}\n`;
    }

    summaryMd += `\n## Distribución por Categoría\n`;
    const sortedCategories = Object.entries(stats.categoryDistribution).sort((a,b) => b[1] - a[1]);
    for (const [k, v] of sortedCategories) {
        summaryMd += `- ${k}: ${v}\n`;
    }

    fs.writeFileSync(path.join(OUT_DIR, 'catalog-curation-summary.md'), summaryMd);
    console.log("Done generating all curated data.");
}

run();

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { createClient } from '@supabase/supabase-js';
import dotenv from 'dotenv';
import { v4 as uuidv4 } from 'uuid';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
dotenv.config({ path: path.resolve(__dirname, '../.env.local') });

const supabase = createClient(process.env.VITE_SUPABASE_URL!, process.env.VITE_SUPABASE_ANON_KEY!);

const rawText = fs.readFileSync('/tmp/raw_catalog.txt', 'utf-8');

function slugify(text: string) {
    return text.toString().toLowerCase()
        .normalize('NFD')
        .replace(/[\u0300-\u036f]/g, '')
        .replace(/\s+/g, '-')
        .replace(/[^\w\-]+/g, '')
        .replace(/\-\-+/g, '-')
        .replace(/^-+/, '')
        .replace(/-+$/, '');
}

const iconsMap: Record<string, { icon: string, color: string }> = {
    "Salud": { icon: "health_and_safety", color: "#be185d" },
    "Finanzas": { icon: "account_balance", color: "#0f766e" },
    "Telecomunicaciones": { icon: "settings_input_antenna", color: "#2563eb" },
    "Retail": { icon: "shopping_bag", color: "#f59e0b" },
    "Moda": { icon: "checkroom", color: "#ec4899" },
    "Comida": { icon: "restaurant", color: "#ef4444" },
    "Transporte": { icon: "commute", color: "#64748b" },
    "Entretenimiento": { icon: "movie", color: "#a855f7" },
    "Bebidas": { icon: "local_bar", color: "#1d4ed8" },
    "Medios": { icon: "campaign", color: "#8b5cf6" },
    "Social / Plataformas": { icon: "share", color: "#06b6d4" },
    "Educación": { icon: "school", color: "#0369a1" },
    "Deportes": { icon: "sports_soccer", color: "#f97316" },
    "Vino": { icon: "wine_bar", color: "#7f1d1d" },
    "Mascotas": { icon: "pets", color: "#ea580c" },
    "Cuidado personal e higiene": { icon: "wash", color: "#0891b2" },
    "Belleza": { icon: "face_retouching_natural", color: "#f43f5e" },
    "Hogar y electrodomésticos": { icon: "home", color: "#65a30d" },
    "Tecnología de consumo": { icon: "devices", color: "#10b981" },
    "Gaming": { icon: "sports_esports", color: "#d946ef" },
    "Bebés y maternidad": { icon: "child_care", color: "#f472b6" },
};

async function run() {
    console.log("🚀 Parsing raw catalog...");
    const lines = rawText.split('\n').map(l => l.trim()).filter(l => l);

    const catalog: any[] = [];
    let currentCat: any = null;
    let currentSub: any = null;

    let idx = 0;
    while (idx < lines.length) {
        const line = lines[idx];
        if (line.startsWith('Categoría:')) {
            const title = line.replace('Categoría:', '').trim();
            currentCat = {
                title,
                id: `cat-${slugify(title)}`,
                slug: slugify(title),
                theme: iconsMap[title] || { icon: 'star', color: '#64748b' },
                subcategories: []
            };
            catalog.push(currentCat);
            idx++;
        } else if (line.startsWith('Subcategoría:')) {
            const label = line.replace('Subcategoría:', '').trim();
            currentSub = {
                id: slugify(label),
                label,
                slug: slugify(label),
                icon: 'label',
                options: []
            };
            currentCat.subcategories.push(currentSub);
            idx++;
        } else if (line.startsWith('Opciones:')) {
            idx++;
            while (idx < lines.length && !lines[idx].startsWith('Categoría:') && !lines[idx].startsWith('Subcategoría:')) {
                const optLine = lines[idx];
                const parts = optLine.split(' ');
                // last part is domain
                const domain = parts.pop();
                const optName = parts.join(' ');
                currentSub.options.push({ name: optName, domain });
                idx++;
            }
        } else {
            idx++; // skip unknown lines
        }
    }

    console.log("🧹 Erasing current data via RPC or raw calls...");

    // We do sequential delete. Supabase limits delete to chunks or we need match. 
    // It's safer to delete where id is not null

    console.log("- Deleting signal events...");
    await supabase.from('signal_events').delete().neq('id', '00000000-0000-0000-0000-000000000000');

    console.log("- Deleting battle options...");
    await supabase.from('battle_options').delete().neq('id', '00000000-0000-0000-0000-000000000000');

    console.log("- Deleting battles...");
    await supabase.from('battles').delete().neq('id', '00000000-0000-0000-0000-000000000000');

    console.log("- Deleting entities...");
    await supabase.from('entities').delete().neq('name', 'none_xyz_fake');

    console.log("✅ DB Cleared.");

    console.log("📝 Generating industries.ts...");
    let code = `export const PARENT_INDUSTRIES: Record<string, any> = {\n`;
    for (const cat of catalog) {
        code += `    "${cat.slug}": {\n`;
        code += `        "id": "${cat.id}",\n`;
        code += `        "title": "${cat.title}",\n`;
        code += `        "subtitle": "Descubre las tendencias en ${cat.title}.",\n`;
        code += `        "theme": {\n`;
        code += `            "primary": "${cat.theme.color}",\n`;
        code += `            "accent": "${cat.theme.color}",\n`;
        code += `            "bgGradient": "from-[${cat.theme.color}]/10 to-white",\n`;
        code += `            "icon": "${cat.theme.icon}"\n`;
        code += `        },\n`;
        code += `        "subcategories": [\n`;
        cat.subcategories.forEach((sub: any, sIdx: number) => {
            code += `            {\n`;
            code += `                "id": "${sub.id}",\n`;
            code += `                "label": "${sub.label}",\n`;
            code += `                "slug": "${sub.slug}",\n`;
            code += `                "icon": "auto_awesome"\n`;
            code += `            }${sIdx < cat.subcategories.length - 1 ? ',' : ''}\n`;
        });
        code += `        ]\n`;
        code += `    },\n`;
    }
    code += `};\n`;

    const destPath = path.resolve(__dirname, '../src/features/feed/data/industries.ts');
    fs.writeFileSync(destPath, code);
    console.log("✅ industries.ts updated.");

    console.log("🌱 Seeding entities and battles...");

    // Convert to flat list for entities
    const entitiesToInsert: any[] = [];
    const allOptionsBySubcat: Record<string, any[]> = {};

    for (const cat of catalog) {
        for (const sub of cat.subcategories) {
            allOptionsBySubcat[sub.slug] = [];
            for (const opt of sub.options) {
                const ent = {
                    id: uuidv4(),
                    name: opt.name,
                    slug: slugify(opt.name),
                    type: 'brand',
                    category: sub.slug, // Subcategory slug represents the "category" in DB
                    metadata: { brand_domain: opt.domain } // stash domain here temporarily
                };
                entitiesToInsert.push(ent);
                allOptionsBySubcat[sub.slug].push(ent);
            }
        }
    }

    // Insert entities in batches
    for (let i = 0; i < entitiesToInsert.length; i += 100) {
        const batch = entitiesToInsert.slice(i, i + 100).map(e => ({ name: e.name, slug: e.slug, type: e.type, category: e.category }));
        const { error } = await supabase.from('entities').insert(batch);
        if (error) { 
            console.error("Error inserting entities:", error);
            process.exit(1);
        }
    }

    // Must fetch them back to get DB-generated IDs if our manual UUID isn't accepted (but it is if we used the generated ones? actually wait DB generates UUIDs)
    // Actually our entity insert doesn't provide IDs. Let's provide IDs.
    await supabase.from('entities').delete().neq('name', ''); // clean again to be safe
    for (let i = 0; i < entitiesToInsert.length; i += 100) {
        const batch = entitiesToInsert.slice(i, i + 100);
        // We will insert with IDs directly to know them
        const { error } = await supabase.from('entities').insert(batch.map(e => ({ id: e.id, name: e.name, slug: e.slug, type: e.type, category: e.category })));
        if(error) console.error("Error batch:", error);
    }

    console.log("⚔️ Generating versus battles per subcategory...");
    // For each subcategory, we create round-robin all vs all (or shuffle to create pairs)
    const battlesToInsert: any[] = [];
    const battleOptionsToInsert: any[] = [];

    for (const [subSlug, entities] of Object.entries(allOptionsBySubcat)) {
        if (entities.length < 2) continue;

        // Shuffle entities
        const shuffled = [...entities].sort(() => 0.5 - Math.random());

        const subcatLabel = subSlug;
        // find parent to get proper titles
        const parentCat = catalog.find(c => c.subcategories.some((s:any) => s.slug === subSlug));

        for (let i = 0; i < shuffled.length; i += 2) {
            if (i + 1 >= shuffled.length) break;

            const A = shuffled[i];
            const B = shuffled[i + 1];

            const battleId = uuidv4();
            battlesToInsert.push({
                id: battleId,
