}

function slugify(text: string) {
    return text.toString().toLowerCase()
        .normalize('NFD')
        .replace(/[̀-ͯ]/g, '')
        .replace(/\s+/g, '-')
        .replace(/[^\w\-]+/g, '')
        .replace(/\-\-+/g, '-')
        .replace(/^-+/, '')
        .replace(/-+$/, '');
}

async function ensureCategoryExists(subcategoryName: string) {
    const slug = slugify(subcategoryName);

    // Check if it exists
    const { data } = await supabase.from('categories').select('id, slug').eq('slug', slug).single();
    if (data) return data;

    // Create it
    const { data: newCat, error } = await supabase.from('categories').insert({
        name: subcategoryName,
        slug: slug,
        emoji: '✨',
        active: true,
        generation_mode: 'ai_curated_pairs'
    }).select('id, slug').single();

    if (error) {
        console.error("Error creating category:", slug, error);
        throw error;
    }
    return newCat;
}

async function nukeOldBattles() {
    console.log("Nukeando batallas antiguas generadas por IA...");
    // We only delete battles that were auto-generated or all active?
    // According to the plan, we delete all autogenerated battles to start fresh.
    // The previous script created battles but they might have had 'active' status.
    // Let's delete all battles since we are starting fresh with V3 catalog.
    const { error } = await supabase.from('battles').delete().neq('id', '00000000-0000-0000-0000-000000000000'); // match all
    if (error) {
        console.error("Error al borrar batallas:", error.message);
    } else {
        console.log("Todas las batallas antiguas borradas.");
    }
}

async function generateAllVersus() {
  console.log("=========================================");
  console.log("INICIANDO GENERACIÓN MASIVA DE VERSUS LOCAL (V3)");
  console.log("=========================================\n");

  try {
    await nukeOldBattles();

    // 1. Obtener TODAS las marcas de V3
    const { data: entities, error: entError } = await supabase
        .from('entities')
        .select('*')
        .eq('type', 'brand')
        .not('metadata->subcategory', 'is', null);

    if (entError) throw entError;

    if (!entities || entities.length === 0) {
        console.log("No se encontraron entidades V3.");
        return;
    }

    // 2. Agrupar por subcategoria
    const groupedBySubcategory: Record<string, any[]> = {};
    entities.forEach(ent => {
        const subcat = ent.metadata?.subcategory;
        if (subcat) {
            if (!groupedBySubcategory[subcat]) groupedBySubcategory[subcat] = [];
            groupedBySubcategory[subcat].push(ent);
        }
    });

    let totalCreated = 0;

    for (const [subcategoryName, brands] of Object.entries(groupedBySubcategory)) {
        if (brands.length < 2) {
            console.log(`Omitiendo ${subcategoryName}: solo ${brands.length} marcas.`);
            continue;
        }

        console.log(`\nProcesando subcategoría: ${subcategoryName} (${brands.length} marcas)`);
        const categoryDoc = await ensureCategoryExists(subcategoryName);

        // 3. Generar combinaciones N*(N-1)/2
        let createdInProgress = 0;
        for (let i = 0; i < brands.length; i++) {
            for (let j = i + 1; j < brands.length; j++) {
                const brandA = brands[i];
                const brandB = brands[j];

                if (brandA.name.toLowerCase().trim() === brandB.name.toLowerCase().trim()) continue;

                // Crear Batalla
                const finalTitle = `Batalla: ${brandA.name} vs ${brandB.name}`;
                const finalDescription = `¿Cuál prefieres entre ${brandA.name} y ${brandB.name}?`;
                const slug = generateSlug(finalTitle);

                const { data: newBattle, error: battleError } = await supabase
                    .from('battles')
                    .insert({
                        slug: slug,
                        title: finalTitle,
                        description: finalDescription,
                        category_id: categoryDoc.id,
                        status: 'active'
                    })
                    .select('*')
                    .single();

                if (battleError || !newBattle) {
                    console.error(`  [X] Error creando batalla ${finalTitle}:`, battleError);
                    continue;
                }

                // Crear opciones
                const { error: optionsError } = await supabase
                    .from('battle_options')
                    .insert([
                        {
                            battle_id: newBattle.id,
                            label: brandA.name,
                            brand_id: brandA.id,
                            image_url: brandA.image_url,
                            sort_order: 1
                        },
                        {
                            battle_id: newBattle.id,
                            label: brandB.name,
                            brand_id: brandB.id,
                            image_url: brandB.image_url,
                            sort_order: 2
                        }
                    ]);

                if (optionsError) {
                    console.error(`  [X] Error creando opciones para ${finalTitle}:`, optionsError);
                    continue;
                }

                // Crear instancia
                const { error: instanceError } = await supabase
                    .from('battle_instances')
                    .insert({
                        battle_id: newBattle.id,
                        version: 1,
                        starts_at: new Date().toISOString()
                    });

                if (instanceError) {
                    console.error(`  [X] Error creando instancia para ${finalTitle}:`, instanceError);
                    continue;
                }

                console.log(`  [+] Creada: ${brandA.name} vs ${brandB.name}`);
                createdInProgress++;
                totalCreated++;

                await new Promise(resolve => setTimeout(resolve, 20));
            }
        }
        console.log(`  -> Se crearon ${createdInProgress} batallas en ${subcategoryName}.`);
    }

    console.log("\n=========================================");
    console.log(`🎉 GENERACIÓN MASIVA FINALIZADA. TOTAL CREADAS: ${totalCreated}`);
    console.log("=========================================\n");

  } catch (error) {
    console.error("Error al generar versus:", error);
  }
}

generateAllVersus();

import { createClient } from '@supabase/supabase-js';
import * as dotenv from 'dotenv';
import { resolve } from 'path';
import OpenAI from 'openai';

dotenv.config({ path: resolve(process.cwd(), '.env.development.local') });

const supabaseUrl = process.env.VITE_SUPABASE_URL || '';
const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.VITE_SUPABASE_ANON_KEY || '';
const openAiKey = process.env.OPENAI_API_KEY || '';

if (!supabaseUrl || !supabaseKey || !openAiKey) {
  console.error("Faltan variables de entorno (Supabase u OpenAI).");
  process.exit(1);
}

const supabase = createClient(supabaseUrl, supabaseKey);
const openai = new OpenAI({ apiKey: openAiKey });

async function main() {
    console.log("Fetching ALL categories...");
    const { data: categories, error } = await supabase.from('categories').select('id, name');

    if (error || !categories) {
        console.error("Error fetching categories", error);
        return;
    }

    const targetCats = categories;
    console.log(`Found ${targetCats.length} categories to process.`);

    const chunkSize = 20;
    const categoryToTitles: Record<string, string[]> = {};

    for (let i = 0; i < targetCats.length; i += chunkSize) {
        const chunk = targetCats.slice(i, i + chunkSize);
        console.log(`\nProcessing chunk ${Math.floor(i/chunkSize) + 1} of ${Math.ceil(targetCats.length / chunkSize)}...`);

        const catNames = chunk.map(c => c.name).join(", ");

        const prompt = `
        Genera 5 frases cortas, directas y punzantes (con humor o ironía fina) para cada una de las siguientes categorías de productos/servicios. 
        Estas frases se usarán como título de una tarjeta (UI) donde el usuario debe elegir entre dos marcas de esa categoría.
        REGLAS ESTRICTAS:
        - NUNCA usar la palabra "batalla", "versus", "combate", "pelea", "duelo" o similares.
        - Las frases deben ser directas y al grano. Preferiblemente afirmaciones o dilemas rápidos, no necesariamente preguntas.
        - Mantenlo corto (máximo 4-8 palabras).
        - NUNCA incluyas marcadores de posición tipo [Marca A] o [Marca B].
        - Las frases deben tener variedad.
        - Evita comillas dobles en los textos si no es estrictamente necesario, para no romper el JSON.
        - Ejemplo para categoría "Bebidas": "Para apagar ese incendio", "El verdadero sabor a verano", "Sed de la buena".
        - Ejemplo para categoría "Bancos": "Tu plata, tus reglas", "El mal menor a fin de mes", "Donde duele menos pagar".

        Categorías a procesar:
        ${catNames}

        Devuelve el resultado ÚNICAMENTE en este formato JSON exacto sin texto adicional:
        {
           "Categoría Exacta 1": ["frase 1", "frase 2", "frase 3", "frase 4", "frase 5"]
        }
        Asegúrate de que las llaves (keys) del JSON sean *exactamente* los nombres de categorías listados arriba.
        `;

        try {
            const completion = await openai.chat.completions.create({
                model: "gpt-4o-mini",
                messages: [{ role: "user", content: prompt }],
                response_format: { type: "json_object" },
                temperature: 0.8
            });

            const resultText = completion.choices[0].message.content || "{}";
            const parsed = JSON.parse(resultText);
            Object.assign(categoryToTitles, parsed);
        } catch (e) {
            console.error("Error with OpenAI:", e);
        }
    }

    console.log("\nGenerated AI titles mapping. Showing preview:");
    console.log(Object.keys(categoryToTitles).slice(0, 3).map(k => `${k}: ${categoryToTitles[k][0]}`).join('\n'));
    console.log("\nNow updating all battles...");

    let totalUpdated = 0;

    for (const cat of targetCats) {
        const titles = categoryToTitles[cat.name];
        if (!titles || titles.length === 0) continue;

        // Fetch ALL battles for this category using pagination
        let allBattles: any[] = [];
        let page = 0;
        let hasMore = true;

        while (hasMore) {
            const { data: pageData, error } = await supabase
                .from('battles')
                .select('id')
                .eq('category_id', cat.id)
                .range(page * 1000, (page + 1) * 1000 - 1);

            if (error) {
                console.error("Error fetching battles page:", error);
                break;
            }
            if (pageData && pageData.length > 0) {
                allBattles = allBattles.concat(pageData);
                page++;
            } else {
                hasMore = false;
            }
        }

        if (allBattles.length === 0) continue;

        let catUpdatedCount = 0;

        // We update in parallel batches of 50 to speed it up
        const parallelLimit = 50;
        for (let i = 0; i < allBattles.length; i += parallelLimit) {
            const batch = allBattles.slice(i, i + parallelLimit);
            await Promise.all(batch.map(async (b) => {
                const randomTitle = titles[Math.floor(Math.random() * titles.length)];
                await supabase.from('battles').update({
                    title: randomTitle,
                    description: null 
                }).eq('id', b.id);
            }));

            catUpdatedCount += batch.length;
            totalUpdated += batch.length;
            process.stdout.write(".");
        }
        console.log(`\n  [OK] Updated ${catUpdatedCount} battles for "${cat.name}"`);
    }

    console.log(`\n========================================`);
    console.log(`DONE! Updated ${totalUpdated} battles globally with AI humor.`);
    console.log(`========================================`);
}

main();

import { useEffect, useMemo, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { supabase } from '../../../supabase/client';
import { accessGate } from '../services/accessGate';
import FeedbackFab from '../../../components/ui/FeedbackFab';
import { track, trackPage } from "../../telemetry/track";

function getNext(search: string) {
    const params = new URLSearchParams(search);
    const next = params.get('next');
    return next && next.startsWith('/') ? next : '/';
}

export default function AccessGatePage() {
    const nav = useNavigate();
    const loc = useLocation();

    const nextPath = useMemo(() => getNext(loc.search), [loc.search]);

    useEffect(() => {
        trackPage("access_gate", { next: nextPath });
    }, [nextPath]);

    const [code, setCode] = useState('');
    const [loading, setLoading] = useState(false);
    const [err, setErr] = useState<string | null>(null);

    const daysValid = Number(import.meta.env.VITE_ACCESS_GATE_DAYS_VALID ?? '30');

    useEffect(() => {
        if (accessGate.isEnabled() && accessGate.hasAccess()) {
            nav(nextPath, { replace: true });
        }
    }, [nextPath, nav]);

    const submit = async (e: React.FormEvent) => {
        e.preventDefault();
        setErr(null);

        const normalized = code.trim().toUpperCase();
        if (!normalized) {
            track("access_gate_submit_missing_code", "warn");
            setErr('Ingresa tu código.');
            return;
        }

        track("access_gate_submit", "info", { code_len: normalized.length, next: nextPath });
        setLoading(true);
        try {
            // 1) Validar en modo anon (NO consumir / NO claim)
            const { data: isValid, error: vErr } = await (supabase as any).rpc('validate_invitation', {
                p_code: normalized,
            });
            if (vErr) throw vErr;

            if (!isValid) {
                track("access_gate_code_invalid", "warn", { code_len: normalized.length, next: nextPath });
                setErr('Ese código ya venció o no existe. Pide uno nuevo.');
                return;
            }

            // 2) Guardar pase local para permitir navegar el piloto (sin quemar el código)
            accessGate.grant(`CODE:${normalized}`, Number.isFinite(daysValid) ? daysValid : 30);
            track("access_gate_granted_local", "info", { days_valid: daysValid, next: nextPath });

            // 3) Entrar
            nav(nextPath, { replace: true });
        } catch (e: any) {
            track("access_gate_error", "error", { message: String(e?.message || "unknown").slice(0, 160) });
            setErr(e?.message ?? 'Ese código no calza. Revisa y prueba de nuevo.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-white flex items-center justify-center px-4">
            <div className="w-full max-w-md">
                <div className="bg-white border border-slate-200 rounded-3xl p-8 shadow-xl shadow-slate-200/50 transition-shadow hover:shadow-2xl hover:shadow-slate-200/60">
                    <h1 className="text-xl font-black text-slate-900">Acceso por invitación</h1>
                    <p className="text-sm text-slate-500 font-medium mt-1">
                        Si tienes código, entra. Si no, comunícate con un administrador.
                    </p>

                    <form onSubmit={submit} className="space-y-4 mt-6">
                        <div>
                            <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">
                                Código de invitación
                            </label>
                            <input
                                value={code}
                                onChange={(e) => setCode(e.target.value)}
                                placeholder="Ej: OPINA-7F3K"
                                className="w-full mt-2 px-4 py-3 rounded-xl border border-slate-200 focus:border-primary-500 focus:ring-4 focus:ring-primary-500/10 outline-none transition-all font-bold text-slate-900 uppercase"
                                autoFocus
                            />
                            <p className="text-[11px] text-slate-500 mt-2 font-medium">Respeta mayúsculas y guiones.</p>
                            {err && <p className="text-sm text-red-600 mt-2 font-medium">{err}</p>}
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full py-3.5 rounded-xl bg-primary hover:opacity-90 text-white font-black transition-all disabled:opacity-50 shadow-sm"
                        >
                            {loading ? 'Verificando código…' : 'Entrar'}
                        </button>

                        {/* Admin bypass (visible para todos, valida rol en el click) */}
                        <div className="mt-4 border-t border-slate-100 pt-4">
                            <button
                                type="button"
                                onClick={async () => {
                                    try {
                                        // Validar primero si hay una sesión activa real de Supabase
                                        const { data: { user: currentUser } } = await supabase.auth.getUser();

                                        if (!currentUser || currentUser.is_anonymous) {
                                            nav('/admin-login');
                                            return;
                                        }

                                        // Requiere que exista tabla users con role y que el usuario ya esté autenticado
                                        const { data, error } = await supabase
                                            .from("users")
                                            .select("role")
                                            .eq("user_id", currentUser.id)
                                            .single();

                                        if (error) {
                                            nav('/admin-login');
                                            return;
                                        }

                                        if ((data as any)?.role === "admin") {
                                            track("access_gate_admin_bypass", "info");
                                            localStorage.setItem("opina_access_pass", "admin");
                                            window.location.href = "/";
                                        } else {
                                            nav('/admin-login');
                                        }
                                    } catch (err) {
                                        nav('/admin-login');
                                    }
                                }}
                                className="w-full flex items-center justify-center gap-2 rounded-xl border border-slate-200 bg-white px-4 py-3 text-sm font-bold text-slate-600 hover:bg-slate-50 hover:text-primary-600 hover:border-primary-200 transition-all shadow-sm"
                            >
                                <span className="material-symbols-outlined text-sm">shield_person</span>
                                Ingreso Administrador
                            </button>
                        </div>
                    </form>
                </div>

                {/* Helper text de invitación en vez de tag piloto */}
                <div className="mt-8 flex flex-col items-center gap-3">
                    <p className="text-[11px] font-medium text-slate-500">
                        ¿Necesitas un código? Pídelo a quien te invitó.
                    </p>
                    <button
                        onClick={() => nav('/')}
                        className="text-[12px] font-bold text-slate-400 hover:text-primary-600 transition-colors uppercase tracking-wider"
                    >
                        Volver al inicio
                    </button>
                </div>
            </div>
            <FeedbackFab />
        </div>
    );
}

