                                            NO
                                        </button>
                                        <button
                                            onClick={() => handleStatusChange(invite.id, invite.status, confirmRowAction.action as any)}
                                            disabled={loading}
                                            className={`px-1.5 py-0.5 rounded text-[10px] font-bold text-white ${confirmRowAction.action === 'delete' ? 'bg-red-600 hover:bg-red-700' :
                                                confirmRowAction.action === 'revoked' ? 'bg-blue-600 hover:bg-blue-700' :
                                                    'bg-emerald-600 hover:bg-emerald-700'
                                                }`}
                                        >
                                            SÍ
                                        </button>
                                    </div>
                                ) : (
                                    <div className="flex items-center justify-center gap-1 flex-nowrap">
                                        {invite.status !== 'revoked' && (
                                            <button
                                                onClick={() => setConfirmRowAction({ id: invite.id, action: 'revoked' })}
                                                disabled={loading}
                                                className="text-[10px] font-bold text-red-600 hover:text-red-700 disabled:opacity-50 focus:outline-none rounded px-1"
                                            >
                                                REVOCAR
                                            </button>
                                        )}
                                        {invite.status === 'revoked' && (
                                            <button
                                                onClick={() => handleStatusChange(invite.id, invite.status, 'active')}
                                                disabled={loading}
                                                className="text-[10px] font-bold text-emerald-600 hover:text-emerald-700 disabled:opacity-50 focus:outline-none rounded px-1"
                                            >
                                                REACTIVAR
                                            </button>
                                        )}
                                        <button
                                            onClick={() => setConfirmRowAction({ id: invite.id, action: 'delete' })}
                                            disabled={loading}
                                            className="text-slate-400 hover:text-red-600 disabled:opacity-50 focus:outline-none rounded px-1 flex items-center justify-center"
                                            title="Eliminar permanentemente"
                                        >
                                            <span className="material-symbols-outlined text-[15px]">delete</span>
                                        </button>
                                    </div>
                                )}
                            </td>
                        </tr>
                    ))
                )}
            </tbody>
        </table>
    );
}

import { useState, useCallback, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Topic, TopicQuestion, TopicStatus, QuestionType } from "../../signals/types/actualidad";
import { adminActualidadService } from "../services/adminActualidadService";
import { logger } from '../../../lib/logger';

export function useActualidadEditor(id: string | undefined) {
    const navigate = useNavigate();
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [topic, setTopic] = useState<Topic | null>(null);

    const [formData, setFormData] = useState<Partial<Topic>>({});
    const [questions, setQuestions] = useState<TopicQuestion[]>([]);
    const [tagsInput, setTagsInput] = useState("");
    const [actorsInput, setActorsInput] = useState("");

    const fetchTopic = useCallback(async () => {
        if (!id) return;
        setLoading(true);
        try {
            const data = await adminActualidadService.getAdminTopicById(id);
            if (data) {
                setTopic(data);
                setFormData({
                    title: data.title,
                    summary: data.summary,
                    impact_phrase: data.impact_phrase || (window as any).impact_quote,
                    category: data.category,
                    intensity: data.intensity,
                    relevance_chile: data.relevance_chile,
                    event_stage: data.event_stage,
                    topic_duration: data.topic_duration,
                    opinion_maturity: data.opinion_maturity,
                    status: data.status,
                    tags: data.tags,
                    actors: data.actors,
                });

                const sortedQ = [...(data.questions || [])].sort((a, b) => a.order - b.order);
                while (sortedQ.length < 3) {
                    const defaultTypes: QuestionType[] = ['scale_0_10', 'single_choice', 'single_choice_polar'];
                    sortedQ.push({
                        id: crypto.randomUUID(),
                        order: sortedQ.length + 1,
                        text: "",
                        type: defaultTypes[sortedQ.length] || 'single_choice',
                        options: []
                    });
                }
                setQuestions(sortedQ.slice(0, 3));
                setTagsInput(data.tags?.join(", ") || "");
                setActorsInput(data.actors?.join(", ") || "");
            }
        } catch (err) {
            logger.error("Error fetching topic", { domain: 'actualidad_editorial', origin: 'useActualidadEditor', action: 'fetch_topic', state: 'failed' }, err);
        } finally {
            setLoading(false);
        }
    }, [id]);

    useEffect(() => {
        fetchTopic();
    }, [fetchTopic]);

    const handleTagsChange = (val: string) => {
        setTagsInput(val);
        setFormData(prev => ({ ...prev, tags: val.split(',').map(t => t.trim()).filter(Boolean) }));
    };

    const handleActorsChange = (val: string) => {
        setActorsInput(val);
        setFormData(prev => ({ ...prev, actors: val.split(',').map(a => a.trim()).filter(Boolean) }));
    };

    const handleQuestionChange = (orderIdx: number, field: string, value: any) => {
        setQuestions(prev => {
            const newQ = [...prev];
            newQ[orderIdx] = { ...newQ[orderIdx], [field]: value };
            return newQ;
        });
    };

    const handleQuestionOptionAdd = (orderIdx: number) => {
        setQuestions(prev => {
            const newQ = [...prev];
            newQ[orderIdx].options = [...(newQ[orderIdx].options || []), "Nueva Opción"];
            return newQ;
        });
    };

    const handleQuestionOptionChange = (orderIdx: number, optIdx: number, value: string) => {
        setQuestions(prev => {
            const newQ = [...prev];
            const newOpts = [...(newQ[orderIdx].options || [])];
            newOpts[optIdx] = value;
            newQ[orderIdx].options = newOpts;
            return newQ;
        });
    };

    const handleQuestionOptionRemove = (orderIdx: number, optIdx: number) => {
        setQuestions(prev => {
            const newQ = [...prev];
            const newOpts = [...(newQ[orderIdx].options || [])];
            newOpts.splice(optIdx, 1);
            newQ[orderIdx].options = newOpts;
            return newQ;
        });
    };

    const validateForm = () => {
        if (!formData.title?.trim()) return "El título es obligatorio.";
        if (!formData.summary?.trim()) return "El resumen neutral es obligatorio.";
        if (!formData.category) return "Debe tener una categoría.";

        for (let i = 0; i < 3; i++) {
            const q = questions[i];
            if (!q.text.trim()) return `La Pregunta ${i + 1} debe tener texto.`;
            if (q.type === 'single_choice' || q.type === 'single_choice_polar') {
                if (!q.options || q.options.length < 2) return `La Pregunta ${i + 1} (${q.type}) requiere al menos 2 opciones.`;
                if (q.options.some(opt => !opt.trim())) return `La Pregunta ${i + 1} tiene opciones vacías.`;
            }
        }
        return null;
    };

    const handleSave = async (silent = false) => {
        if (!topic || !id) return false;

        const err = validateForm();
        if (err) {
            if (!silent) alert(err);
            return false;
        }

        setSaving(true);
        try {
            const updates = { ...formData };
            await adminActualidadService.updateTopicEditorialData(id, updates, true);
            await adminActualidadService.updateTopicQuestions(id, questions);

            setTopic(prev => prev ? { ...prev, ...formData, admin_edited: true } as Topic : null);

            if (!silent) alert("Cambios guardados exitosamente.");
            return true;
        } catch (e) {
            logger.error("Error al guardar cambios de actualidad", { domain: 'actualidad_editorial', origin: 'useActualidadEditor', action: 'save_topic', state: 'failed', topic_id: id }, e);
            if (!silent) alert("Error al guardar cambios.");
            return false;
        } finally {
            setSaving(false);
        }
    };

    const handleStatusChange = async (newStatus: TopicStatus) => {
        if (!id || !topic) return;

        if (newStatus === 'published' || newStatus === 'approved') {
            const saved = await handleSave(true);
            if (!saved) {
                alert("Corrige los errores del formulario antes de transicionar estado.");
                return;
            }
        }

        setSaving(true);
        try {
            const res = await adminActualidadService.updateTopicStatus(id, newStatus);
            if (res.success) {
                setTopic(prev => prev ? { ...prev, status: newStatus } : null);
                setFormData(prev => ({ ...prev, status: newStatus }));
                if (newStatus === 'published') {
                    navigate('/admin/actualidad');
                }
            } else {
                alert(res.error || "No se pudo cambiar el estado.");
            }
        } catch (e) {
            logger.error("Error changing topic status", { domain: 'actualidad_editorial', origin: 'useActualidadEditor', action: 'change_status', state: 'failed', topic_id: id, new_status: newStatus }, e);
        } finally {
            setSaving(false);
        }
    };

    return {
        topic,
        formData,
        setFormData,
        questions,
        tagsInput,
        actorsInput,
        loading,
        saving,
        handleTagsChange,
        handleActorsChange,
        handleQuestionChange,
        handleQuestionOptionAdd,
        handleQuestionOptionChange,
        handleQuestionOptionRemove,
        handleSave,
        handleStatusChange,
        navigate
    };
}

import { useState, useEffect, useMemo, useCallback } from 'react';
import { adminInvitesService, InviteRow, RedemptionRow } from '../services/adminInvitesService';
import { supabase } from '../../../supabase/client';

export type StatusFilterType = 'all' | 'pending' | 'in_use' | 'abandoned' | 'revoked';

export function useAdminInvites() {
    const [tab, setTab] = useState<'invites' | 'redemptions'>('invites');
    const [invites, setInvites] = useState<InviteRow[]>([]);
    const [redemptions, setRedemptions] = useState<RedemptionRow[]>([]);
    const [loading, setLoading] = useState(false);
    const [errorMsg, setErrorMsg] = useState<string | null>(null);
    const [prefix, setPrefix] = useState('OP');
    const [statusFilter, setStatusFilter] = useState<StatusFilterType>('all');
    const [searchTerm, setSearchTerm] = useState('');
    const [selectedInvites, setSelectedInvites] = useState<Set<string>>(new Set());
    const [confirmAction, setConfirmAction] = useState<'active' | 'revoked' | 'delete' | null>(null);
    const [confirmRowAction, setConfirmRowAction] = useState<{ id: string, action: 'active' | 'revoked' | 'delete' } | null>(null);
    const [waDrafts, setWaDrafts] = useState<Record<string, { phone: string; isSending: boolean; statusMsg?: string }>>({});
    const [sortConfig, setSortConfig] = useState<{ key: keyof InviteRow; direction: 'asc' | 'desc' } | null>(null);

    const handleSort = (key: keyof InviteRow) => {
        let direction: 'asc' | 'desc' = 'desc';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'desc') {
            direction = 'asc';
        }
        setSortConfig({ key, direction });
    };

    const sortedInvites = useMemo(() => {
        const sortableItems = [...invites];

        if (sortConfig !== null) {
            sortableItems.sort((a, b) => {
                const aValue = a[sortConfig.key];
                const bValue = b[sortConfig.key];

                if (aValue === null || aValue === undefined) return sortConfig.direction === 'asc' ? -1 : 1;
                if (bValue === null || bValue === undefined) return sortConfig.direction === 'asc' ? 1 : -1;

                if (aValue < bValue) {
                    return sortConfig.direction === 'asc' ? -1 : 1;
                }
                if (aValue > bValue) {
                    return sortConfig.direction === 'asc' ? 1 : -1;
                }
                return 0;
            });
        } else {
             const priority: Record<string, number> = {
                'used': 1,
                'active': 2,
                'revoked': 3
            };

            sortableItems.sort((a, b) => {
                const pA = priority[a.status] || 99;
                const pB = priority[b.status] || 99;

                if (pA !== pB) return pA - pB;

                return new Date(b.created_at).getTime() - new Date(a.created_at).getTime();
            });
        }
        return sortableItems;
    }, [invites, sortConfig]);

    const updateWaDraft = (id: string, updates: Partial<{ phone: string; isSending: boolean; statusMsg?: string }>) => {
        setWaDrafts(prev => ({
            ...prev,
            [id]: { ...(prev[id] || { phone: '', isSending: false }), ...updates }
        }));
    };

    const handleSendWhatsApp = async (invite: InviteRow) => {
        const draft = waDrafts[invite.id];
        if (!draft?.phone || !draft.phone.startsWith('+')) {
            alert('Por favor ingresa un teléfono válido con formato +... (ej: +56912345678)');
            return;
        }

        updateWaDraft(invite.id, { isSending: true, statusMsg: undefined });
        try {
            const res = await adminInvitesService.sendWhatsAppInvite(invite.id, draft.phone);
            if (res.success) {
                updateWaDraft(invite.id, { isSending: false, statusMsg: 'Enviado ✅' });
                setInvites(prev => prev.map(i => i.id === invite.id ? {
                    ...i,
                    whatsapp_phone: draft.phone,
                    whatsapp_status: 'sent',
                    whatsapp_sent_at: new Date().toISOString()
                } : i));
            } else {
                const detailObj = res.detail as { error?: { message?: string } } | undefined;
                const detailMsg = detailObj?.error?.message || res.error || 'Fallo desconocido';
                updateWaDraft(invite.id, { isSending: false, statusMsg: `Error: ${detailMsg.substring(0, 100)}` });
            }
        } catch (err: unknown) {
            updateWaDraft(invite.id, { isSending: false, statusMsg: `Error: ${(err as Error).message}` });
        }
    };

    const fetchInvites = useCallback(async () => {
        setLoading(true);
        setErrorMsg(null);
        try {
            const data = await adminInvitesService.listInvites(statusFilter, searchTerm);
            setInvites(data);
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || 'Error fetching invites');
        } finally {
            setLoading(false);
        }
    }, [statusFilter, searchTerm]);

    const fetchRedemptions = useCallback(async () => {
        setLoading(true);
        setErrorMsg(null);
        try {
            const data = await adminInvitesService.listRedemptions(200);
            setRedemptions(data);
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || 'Error fetching redemptions');
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        setSelectedInvites(new Set());
        setConfirmAction(null);
        setConfirmRowAction(null);
        if (tab === 'invites') fetchInvites();
        else fetchRedemptions();
    }, [tab, statusFilter, fetchInvites, fetchRedemptions]);

    const handleGenerate = async () => {
        setLoading(true);
        setErrorMsg(null);
        try {
            await adminInvitesService.generateInvites(10, prefix);
            await fetchInvites();
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || 'Error generating invites');
        } finally {
            setLoading(false);
        }
    };

    const handleStatusChange = async (inviteId: string, _currentStatus: string, action: 'revoked' | 'active' | 'delete') => {
        setLoading(true);
        setErrorMsg(null);
        setConfirmRowAction(null);
        try {
            if (action === 'delete') {
                await adminInvitesService.deleteInvite(inviteId);
                setInvites(invites.filter((i) => i.id !== inviteId));
            } else {
                const { error } = await (supabase as any).rpc('admin_set_invitation_status', {
                    p_invite_id: inviteId,
                    p_status: action,
                });
                if (error) throw error;
                setInvites(invites.map((i) => i.id === inviteId ? { ...i, status: action } : i));
            }
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || `Error updating invite status to ${action}`);
        } finally {
            setLoading(false);
        }
    };

    const handleCopyActive = async () => {
        const activeCodes = invites
            .filter((i) => i.status === 'active')
            .map((i) => i.code)
            .join('\n');

        if (!activeCodes) {
            setErrorMsg('No active codes to copy');
            return;
        }

        try {
            await navigator.clipboard.writeText(activeCodes);
            alert('Códigos copiados al portapapeles!');
        } catch (err) {
            setErrorMsg('Failed to copy to clipboard');
        }
    };

    const toggleSelectAll = () => {
        if (selectedInvites.size === invites.length && invites.length > 0) {
            setSelectedInvites(new Set());
        } else {
            setSelectedInvites(new Set(invites.map(i => i.id)));
        }
    };

    const toggleSelect = (id: string) => {
        const newSet = new Set(selectedInvites);
        if (newSet.has(id)) newSet.delete(id);
        else newSet.add(id);
        setSelectedInvites(newSet);
    };

    const handleBulkAction = async (action: 'active' | 'revoked' | 'delete') => {
        if (selectedInvites.size === 0) return;

        setLoading(true);
        setErrorMsg(null);
        setConfirmAction(null);
        try {
            const promises = Array.from(selectedInvites).map(async (inviteId) => {
                if (action === 'delete') {
                    return adminInvitesService.deleteInvite(inviteId);
                } else {
                    return (supabase as any).rpc('admin_set_invitation_status', {
                        p_invite_id: inviteId,
                        p_status: action,
                    });
                }
            });

            await Promise.all(promises);

            await fetchInvites();
            setSelectedInvites(new Set());
        } catch (err: unknown) {
            setErrorMsg((err as Error).message || `Error procesando acción masiva`);
        } finally {
            setLoading(false);
        }
    };

    const stats = useMemo(() => {
        const total = invites.length;
        const used = invites.filter(i => i.status === 'used').length;
        const active = invites.filter(i => i.status === 'active').length;
        // Consider abandonment as those sent via WA but not used, or explicitly with abandoned status
        const abandoned = invites.filter(i => i.status === 'abandoned' || (i.status === 'active' && i.whatsapp_status === 'sent')).length;
        const conversionRate = total > 0 ? (used / total) * 100 : 0;

        return { total, used, active, abandoned, conversionRate };
    }, [invites]);

    return {
        tab, setTab,
        invites, redemptions,
        loading, errorMsg,
        prefix, setPrefix,
        statusFilter, setStatusFilter,
        searchTerm, setSearchTerm,
        selectedInvites, setSelectedInvites,
        confirmAction, setConfirmAction,
        confirmRowAction, setConfirmRowAction,
        waDrafts, sortConfig,
        handleSort, sortedInvites,
        updateWaDraft, handleSendWhatsApp,
        fetchInvites, fetchRedemptions,
        handleGenerate, handleStatusChange,
        handleCopyActive, toggleSelectAll, toggleSelect,
        handleBulkAction, stats
    };
}

import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { adminAntifraudService, AntifraudFlagRow, DeviceSummary } from '../services/adminAntifraudService';
import { logger } from '../../../lib/logger';

const AdminAntifraud: React.FC = () => {
    const [flags, setFlags] = useState<AntifraudFlagRow[]>([]);
    const [summaries, setSummaries] = useState<Record<string, DeviceSummary>>({});
    const [loading, setLoading] = useState(true);
    const [loadingSummary, setLoadingSummary] = useState<Record<string, boolean>>({});
    const [error, setError] = useState<string | null>(null);
    const [expandedRowId, setExpandedRowId] = useState<string | null>(null);

    const fetchFlags = async () => {
        try {
            setLoading(true);
            setError(null);
            const data = await adminAntifraudService.listFlags();
            setFlags(data);
        } catch (err: any) {
            setError(err.message || String(err));
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchFlags();
    }, []);

    const handleBanToggle = async (deviceHash: string, currentBanned: boolean) => {
        const isBanning = !currentBanned;
        let reason = '';

        if (isBanning) {
            const input = window.prompt("Motivo del ban (opcional):");
            if (input === null) return; // Cancelled
            reason = input.trim();
        } else {
            const confirmUnban = window.confirm("¿Estás seguro de quitar el ban a este dispositivo?");
            if (!confirmUnban) return; // Cancelled
        }

        try {
            setLoading(true);
            setError(null);
            const result = await adminAntifraudService.setBan(deviceHash, isBanning, reason);

            if (!result.ok) {
                throw new Error(result.error || 'Error al actualizar el ban');
            }

            await fetchFlags(); // Refresh list to get updated row from DB
        } catch (err: any) {
            setError(err.message || String(err));
            setLoading(false); // only set to false on error, fetchFlags handles success
        }
    };

    const toggleExpand = async (id: string, deviceHash: string) => {
        if (expandedRowId === id) {
            setExpandedRowId(null);
            return;
        }

        setExpandedRowId(id);

        // Fetch summary si no se tiene
        if (!summaries[deviceHash]) {
            try {
                setLoadingSummary(prev => ({ ...prev, [deviceHash]: true }));
                const summary = await adminAntifraudService.getDeviceSummary(deviceHash);
                setSummaries(prev => ({ ...prev, [deviceHash]: summary }));
            } catch (err: any) {
                logger.error("Failed to fetch summary", { domain: 'admin_actions', origin: 'AdminAntifraud', action: 'fetch_summary', state: 'failed' }, err);
            } finally {
                setLoadingSummary(prev => ({ ...prev, [deviceHash]: false }));
            }
        }
    };

    const getSeverityBadge = (severity: string) => {
        switch (severity) {
            case 'critical':
                return <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-red-100 text-red-800">Critical</span>;
            case 'warn':
                return <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-yellow-100 text-yellow-800">Warn</span>;
            default:
                return <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-100 text-slate-800">{severity}</span>;
        }
    };

    const getStatusBadge = (active: boolean, banned: boolean) => {
        if (banned) {
            return <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-red-100 text-red-800">Banned</span>;
        }
        if (active) {
            return <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-green-100 text-green-800">Active Warning</span>;
        }
        return <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-100 text-slate-800">Inactive</span>;
    };

    return (
        <div className="max-w-7xl mx-auto p-4 sm:p-6 lg:p-8">
            <div className="sm:flex sm:items-center sm:justify-between mb-8">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900">Control Antifraude</h1>
                    <p className="mt-1 text-sm text-slate-500">
                        Detección de comportamiento anómalo y control de bans por device hash.
                    </p>
                </div>
                <div className="mt-4 sm:mt-0">
                    <button
                        onClick={fetchFlags}
                        disabled={loading}
                        className="inline-flex items-center justify-center px-4 py-2 border border-transparent font-medium rounded-xl shadow-sm text-white bg-primary-600 hover:bg-primary-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary-500 disabled:opacity-50 transition w-full sm:w-auto"
                    >
                        {loading ? 'Refrescando...' : 'Refrescar Lista'}
                    </button>
                </div>
            </div>

            {error && (
                <div className="mb-4 bg-red-50 border-l-4 border-red-400 p-4 rounded-r-md">
                    <div className="flex">
                        <div className="flex-shrink-0">
                            <span className="material-symbols-outlined text-red-400">error</span>
                        </div>
                        <div className="ml-3">
                            <p className="text-sm text-red-700">{error}</p>
                        </div>
                    </div>
                </div>
            )}

            <div className="bg-white shadow-sm ring-1 ring-slate-200 sm:rounded-2xl overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="min-w-full divide-y divide-slate-200">
                        <thead className="bg-slate-50">
                            <tr>
                                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Device Hash</th>
                                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Flag Type</th>
                                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Severity</th>
                                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Status</th>
                                <th scope="col" className="px-6 py-3 text-left text-xs font-medium text-slate-500 uppercase tracking-wider">Updated</th>
                                <th scope="col" className="px-6 py-3 text-right text-xs font-medium text-slate-500 uppercase tracking-wider">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-slate-200">
                            {flags.length === 0 && !loading && (
                                <tr>
                                    <td colSpan={6} className="px-6 py-12 text-center text-sm text-slate-500">
                                        No se encontraron registros de comportamiento anómalo.
                                    </td>
                                </tr>
                            )}
                            {flags.map((flag) => (
                                <React.Fragment key={flag.id}>
                                    <tr className="hover:bg-slate-50 transition-colors">
                                        <td className="px-6 py-4 whitespace-nowrap text-sm font-mono text-slate-900 truncate max-w-[150px]" title={flag.device_hash}>
                                            {flag.device_hash.substring(0, 12)}...
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-700">
                                            {flag.flag_type}
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            {getSeverityBadge(flag.severity)}
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            {getStatusBadge(flag.is_active, flag.banned)}
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500" title={flag.updated_at}>
                                            {new Date(flag.updated_at).toLocaleString()}
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                                            <div className="flex items-center justify-end gap-3">
                                                <button
                                                    onClick={() => toggleExpand(flag.id, flag.device_hash)}
                                                    className="text-primary-600 hover:text-primary-900 transition-colors bg-primary-50 hover:bg-primary-100 px-2.5 py-1 rounded-md"
                                                >
                                                    {expandedRowId === flag.id ? 'Ocultar' : 'Detalles'}
                                                </button>
                                                <button
                                                    onClick={() => handleBanToggle(flag.device_hash, flag.banned)}
                                                    disabled={loading}
                                                    className={`px-3 py-1 rounded-md text-white font-medium shadow-sm transition-all focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 ${flag.banned
                                                        ? 'bg-slate-600 hover:bg-slate-700 focus:ring-slate-500'
                                                        : 'bg-red-600 hover:bg-red-700 focus:ring-red-500'
                                                        }`}
                                                >
                                                    {flag.banned ? 'Unban' : 'Ban'}
                                                </button>
                                            </div>
                                        </td>
                                    </tr>

                                    {/* Expanded Row for Details */}
                                    <AnimatePresence>
                                        {expandedRowId === flag.id && (
                                            <motion.tr
                                                initial={{ opacity: 0, height: 0 }}
                                                animate={{ opacity: 1, height: 'auto' }}
                                                exit={{ opacity: 0, height: 0 }}
                                                transition={{ duration: 0.2 }}
                                            >
                                                <td colSpan={6} className="px-6 py-4 bg-slate-50 border-b border-slate-200">
                                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                                        {/* RAW Details */}
                                                        <div className="text-sm text-slate-800 space-y-2">
                                                            <h4 className="font-semibold text-slate-900">Detalles de Detección</h4>
                                                            <pre className="bg-slate-800 text-slate-100 p-3 rounded-lg overflow-x-auto text-xs font-mono shadow-inner">
                                                                {JSON.stringify(flag.details, null, 2)}
                                                            </pre>
                                                            {flag.banned && flag.banned_reason && (
                                                                <div className="mt-2 text-red-700 bg-red-50 p-2 rounded border border-red-100">
                                                                    <span className="font-semibold">Motivo del Ban:</span> {flag.banned_reason}
                                                                </div>
                                                            )}
                                                            <div className="text-xs text-slate-500 mt-2">
                                                                Full Device Hash: <code className="bg-slate-200 px-1 py-0.5 rounded selectable">{flag.device_hash}</code>
                                                            </div>
                                                        </div>

                                                        {/* Device Activity Summary */}
                                                        <div className="text-sm text-slate-800 space-y-2">
                                                            <h4 className="font-semibold text-slate-900">Actividad del Dispositivo</h4>

                                                            {loadingSummary[flag.device_hash] ? (
                                                                <div className="p-4 flex items-center justify-center text-slate-500 bg-white border border-slate-200 rounded-lg shadow-sm">
                                                                    <div className="w-5 h-5 border-2 border-primary-500 border-t-transparent rounded-full animate-spin mr-2"></div>
                                                                    Cargando métricas...
                                                                </div>
                                                            ) : summaries[flag.device_hash] ? (
                                                                summaries[flag.device_hash].ok ? (
                                                                    <div className="bg-white border border-slate-200 rounded-lg p-3 shadow-sm space-y-2">
                                                                        <div className="flex justify-between items-center py-1 border-b border-slate-100">
                                                                            <span className="text-slate-500">Última Señal:</span>
                                                                            <span className="font-medium">{summaries[flag.device_hash].last_signal_at ? new Date(summaries[flag.device_hash].last_signal_at as string).toLocaleString() : 'N/A'}</span>
                                                                        </div>
                                                                        <div className="flex justify-between items-center py-1 border-b border-slate-100">
                                                                            <span className="text-slate-500">Señales (últimas 24h):</span>
                                                                            <span className="font-medium text-primary-600">{summaries[flag.device_hash].signals_24h}</span>
                                                                        </div>
                                                                        <div className="flex justify-between items-center py-1 border-b border-slate-100">
                                                                            <span className="text-slate-500">Señales vel. (últimos 10m):</span>
                                                                            <span className={`font-medium ${summaries[flag.device_hash].signals_10m! > 20 ? 'text-red-600' : 'text-slate-700'}`}>{summaries[flag.device_hash].signals_10m}</span>
                                                                        </div>
                                                                        <div className="flex justify-between items-center py-1 border-b border-slate-100">
                                                                            <span className="text-slate-500">Usuarios Distintos (24h):</span>
                                                                            <span className={`font-medium ${summaries[flag.device_hash].distinct_users_24h! > 2 ? 'text-blue-600' : 'text-slate-700'}`}>{summaries[flag.device_hash].distinct_users_24h}</span>
                                                                        </div>
                                                                        <div className="flex justify-between items-center py-1">
                                                                            <span className="text-slate-500">Batallas Votadas (24h):</span>
                                                                            <span className="font-medium">{summaries[flag.device_hash].distinct_battles_24h}</span>
                                                                        </div>
