import { supabase } from '../../../supabase/client';
import { logger } from '../../../lib/logger';
import { Topic, TopicQuestion, TopicStatus, AiTopicPayload, validateAiTopicPayload } from '../../signals/types/actualidad';

export const adminActualidadService = {
  /**
   * Obtener listado de temas filtrado por estado
   */
  async getAdminTopics(status: TopicStatus | 'all' = 'all'): Promise<Topic[]> {
    try {
      let query = supabase
        .from('current_topics')
        .select('*')
        .order('created_at', { ascending: false });

      if (status !== 'all') {
        const statusesToQuery = status === 'detected' ? ['detected', 'draft'] : [status];
        query = query.in('status', statusesToQuery);
      }

      const { data, error } = await query;

      if (error) {
        logger.error('Error al obtener temas de actualidad (Admin)', { error });
        throw error;
      }

      return data.map((d: { short_summary?: string | null; impact_quote?: string | null; [key: string]: unknown }) => ({
        ...d,
        summary: d.short_summary,
        impact_phrase: d.impact_quote
      })) as unknown as Topic[];
    } catch (e) {
      logger.error('Error inesperado en getAdminTopics', { error: e });
      return [];
    }
  },

  /**
   * Obtener un tema por id con sus preguntas (y options)
   */
  async getAdminTopicById(id: string): Promise<Topic | null> {
    try {
      const { data: topic, error: topicError } = await supabase
        .from('current_topics')
        .select('*')
        .eq('id', id)
        .single();

      if (topicError || !topic) return null;

      // Obtener preguntas
      const { data: set } = await supabase
        .from('topic_question_sets')
        .select('id')
        .eq('topic_id', id)
        .single();

      let questions: TopicQuestion[] = [];
      if (set) {
        const { data: qData } = await supabase
          .from('topic_questions')
          .select('*')
          .eq('set_id', set.id)
          .order('question_order', { ascending: true });

        if (qData) {
          questions = qData.map(q => ({
            id: q.id,
            order: q.question_order,
            text: q.question_text,
            type: q.answer_type as TopicQuestion['type'],
            options: q.options_json as TopicQuestion['options']
          }));
        }
      }

      return {
        ...(topic as Record<string, unknown>),
        summary: topic.short_summary,
        impact_phrase: topic.impact_quote,
        questions
      } as unknown as Topic;
    } catch (e) {
      logger.error('Error inesperado en getAdminTopicById', { error: e });
      return null;
    }
  },

  /**
   * Crear tema detectado desde Payload IA (Guardando snapshot en metadata)
   */
  async createTopicFromDetectedAiPayload(payload: AiTopicPayload): Promise<string | null> {
    try {
      // 1. Generar slug único básico
      const baseSlug = payload.title.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim().replace(/\s+/g, '-');
      const slug = `${baseSlug}-${Math.floor(Math.random() * 1000)}`;

      // 2. Extraer dominio simple para source_domain
      let domain = '';
      try {
        if (payload.source_url) {
          domain = new URL(payload.source_url).hostname.replace('www.', '');
        }
      } catch { /* ignore */ }

      // 3. Crear Topic
      const metadataSnapshot = { raw_ai_payload: payload, source_url: payload.source_url };

      const { data: topicData, error: topicError } = await supabase
        .from('current_topics')
        .insert([{
          slug,
          title: payload.title,
          short_summary: payload.summary,
          category: payload.category,
          status: 'detected',
          impact_quote: payload.impact_phrase,
          tags: payload.tags || [],
          actors: payload.actors || [],
          intensity: payload.intensity || 1,
          relevance_chile: payload.relevance_chile || 3,
          confidence_score: payload.confidence_score || 0,
          event_stage: payload.event_stage || 'announcement',
          topic_duration: payload.topic_duration || 'short',
          opinion_maturity: payload.opinion_maturity || 'low',
          source_domain: domain,
          created_by_ai: true,
          admin_edited: false,
          metadata: metadataSnapshot as unknown as Exclude<unknown, undefined>
        } as never])
        .select('id')
        .single();

      if (topicError || !topicData) throw topicError;

      const topicId = topicData.id;

      // 4. Asegurar Questions
      if (payload.questions && Array.isArray(payload.questions)) {
        await this.updateTopicQuestions(topicId, payload.questions);
      }

      return topicId;
    } catch (e) {
      logger.error('Error al crear tema detectado a partir del Payload IA', { error: e });
      return null;
    }
  },

  /**
   * Ingesta segura de payload IA.
   * Sanitiza, valida estrictamente, y verifica duplicados.
   */
  async ingestAiTopicPayload(payload: unknown): Promise<{ success: boolean; topicId?: string; errors?: string[] }> {
    try {
      // 1. Validación de estructura base
      const errors = validateAiTopicPayload(payload);
      if (errors.length > 0) {
        return { success: false, errors };
      }

      // Asegurar tipado tras validación
      const cleanPayload = payload as AiTopicPayload;

      // 2. Sanitización (limpiar strings, espacios)
      cleanPayload.title = cleanPayload.title.trim();
      cleanPayload.summary = cleanPayload.summary.trim();
      cleanPayload.impact_phrase = cleanPayload.impact_phrase?.trim() || "Sin impacto definido";
      cleanPayload.source_url = cleanPayload.source_url.trim();

      // 3. Verificación de duplicados estrictos (URL idéntico)
      const { data: dupUrl } = await supabase
        .from('current_topics')
        .select('id')
        .eq('metadata->>source_url', cleanPayload.source_url)
        .limit(1);

      if (dupUrl && dupUrl.length > 0) {
        return { success: false, errors: ['El source_url ya existe en la base de datos (Duplicado exacto).'] };
      }

      // 4. Verificación de duplicados por título (Similar en últimos 3 días)
      const threeDaysAgo = new Date();
      threeDaysAgo.setDate(threeDaysAgo.getDate() - 3);

      const { data: dupTitle } = await supabase
        .from('current_topics')
        .select('id')
        .ilike('title', cleanPayload.title)
        .gte('created_at', threeDaysAgo.toISOString())
        .limit(1);

      if (dupTitle && dupTitle.length > 0) {
        return { success: false, errors: ['Un tema con título muy similar fue creado en los últimos 3 días (Posible tema repetido).'] };
      }

      // 5. Persistir usando la capa existente
      const topicId = await this.createTopicFromDetectedAiPayload(cleanPayload);

      if (!topicId) {
        return { success: false, errors: ['Error interno al persistir en base de datos.'] };
      }

      return { success: true, topicId };

    } catch (e: unknown) {
      logger.error('Fallo grave en capa de ingestión IA', { error: e });
      return { success: false, errors: [(e as Error).message || 'Excepción desconocida durante ingestión'] };
    }
  },

  /**
   * Guardar tema genérico con preguntas
   */
  async createTopicWithQuestions(topic: Partial<Topic>, questions: TopicQuestion[]): Promise<string | null> {
    try {
      const slug = topic.title?.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim().replace(/\s+/g, '-') + '-' + Math.floor(Math.random() * 1000);

      const { data: topicData, error: topicError } = await supabase
        .from('current_topics')
        .insert([{
          slug: topic.slug || slug,
          title: topic.title,
          short_summary: topic.summary,
          category: topic.category || 'País',
          status: topic.status || 'detected',
          impact_quote: topic.impact_phrase,
          tags: topic.tags || [],
          actors: topic.actors || [],
          intensity: topic.intensity || 1,
          relevance_chile: topic.relevance_chile || 3,
          confidence_score: topic.confidence_score,
          event_stage: topic.event_stage || 'discussion',
          topic_duration: topic.topic_duration || 'short',
          opinion_maturity: topic.opinion_maturity || 'low',
          source_domain: topic.source_domain,
          metadata: { source_url: topic.source_url } as unknown as Exclude<unknown, undefined>
        } as never])
        .select('id')
        .single();

      if (topicError || !topicData) throw topicError;

      await this.updateTopicQuestions(topicData.id, questions);
      return topicData.id;
    } catch (e) {
      logger.error('Error al guardar tema genérico', { error: e });
      return null;
    }
  },

  /**
   * Actualizar metadatos editoriales del tema. Marca automáticamente admin_edited=true
   */
  async updateTopicEditorialData(id: string, updates: Partial<Topic>, markAsAdminEdited: boolean = true): Promise<boolean> {
    try {
      const dbUpdates: Record<string, unknown> = { ...updates };
      // Map frontend interface to DB schema if needed
      if (updates.summary !== undefined) {
        dbUpdates.short_summary = updates.summary;
        delete dbUpdates.summary;
      }
      if (updates.impact_phrase !== undefined) {
        dbUpdates.impact_quote = updates.impact_phrase;
        delete dbUpdates.impact_phrase;
      }

      if (markAsAdminEdited) {
        dbUpdates.admin_edited = true;
      }

      // Avoid trying to update relations directly
      delete dbUpdates.questions; 
      delete dbUpdates.id;
      delete dbUpdates.created_at;
      delete dbUpdates.updated_at;

      const { error } = await supabase
        .from('current_topics')
        .update(dbUpdates)
        .eq('id', id);

      if (error) throw error;
      return true;
    } catch (e) {
      logger.error(`Error al actualizar data editorial del tema ${id}`, { error: e });
      return false;
    }
  },

  /**
   * Actualizar o sobreescribir las preguntas de un tema
   */
  async updateTopicQuestions(topicId: string, questions: TopicQuestion[]): Promise<boolean> {
    try {
      // 1. Obtener o crear setId
      let { data: set } = await supabase
        .from('topic_question_sets')
        .select('id')
        .eq('topic_id', topicId)
        .single();

      if (!set) {
        const { data: newSet, error: setError } = await supabase
          .from('topic_question_sets')
          .insert([{ topic_id: topicId }])
          .select('id')
          .single();
        if (setError || !newSet) throw setError || new Error('No se pudo crear Question Set');
        set = newSet;
      }

      // 2. Extraer IDs de las preguntas enviadas que YA existen
      const incomingIds = questions.filter(q => q.id).map(q => q.id!);

      // 3. Eliminar las preguntas que están en la base de datos pero NO en la lista entrante
      if (incomingIds.length > 0) {
        const { error: delError } = await supabase
          .from('topic_questions')
          .delete()
          .eq('set_id', set.id)
          .not('id', 'in', `(${incomingIds.join(',')})`);
        if (delError) throw delError;
      } else {
        // Si no vienen IDs, borrar todo
        const { error: delError } = await supabase
          .from('topic_questions')
          .delete()
          .eq('set_id', set.id);
        if (delError) throw delError;
      }

      // 4. Preparar UPSERT
      const questionsToUpsert = questions.map(q => {
        const payload: Record<string, unknown> = {
          set_id: set!.id,
          question_order: q.order,
          question_text: q.text,
          answer_type: q.type,
          options_json: q.options || []
        };
        // Si tiene un UUID, lo pasamos para UPSERT
        if (q.id) {
          payload.id = q.id;
        }
        return payload;
      });

      if (questionsToUpsert.length > 0) {
        const { error: upsertError } = await supabase
          .from('topic_questions')
          .upsert(questionsToUpsert as any[], { onConflict: 'id' });
        if (upsertError) throw upsertError;
      }

      return true;
    } catch (e) {
      logger.error(`Error actualizando preguntas para el tema ${topicId}`, { error: e });
      return false;
    }
  },

  /**
   * Actualizar estado editorial (Detectado -> Aprobado -> Publicado, Archivación, etc)
   * Incluye defensas críticas para pubicaciones.
   */
  async updateTopicStatus(id: string, nextStatus: TopicStatus): Promise<{ success: boolean; error?: string }> {
    try {
      // Regla estricta antes de aprobar o publicar
      if (nextStatus === 'approved' || nextStatus === 'published') {
        const topic = await this.getAdminTopicById(id);
        if (!topic) return { success: false, error: 'Tema no existe' };

        // Simular validación editorial estricta
        if (!topic.title || topic.title.trim() === '') return { success: false, error: 'El tema requiere un título válido.' };
        if (!topic.summary || topic.summary.trim() === '') return { success: false, error: 'Falta un resumen neutral para su publicación.' };
        if (!topic.category) return { success: false, error: 'Falta configurar una categoría válida.' };

        // Validación de preguntas asociadas
        if (!topic.questions || topic.questions.length !== 3) {
            return { success: false, error: 'La arquitectura requiere STRICTAMENTE 3 preguntas para ser operado, no ' + (topic.questions?.length || 0) };
        }
        for (const [idx, q] of topic.questions.entries()) {
            if (!q.text || q.text.trim() === '') return { success: false, error: `La pregunta ${idx + 1} no tiene texto.` };
            if (['single_choice', 'single_choice_polar'].includes(q.type) && (!q.options || q.options.length < 2)) {
                return { success: false, error: `La pregunta ${idx + 1} (${q.type}) requiere al menos 2 alternativas establecidas.` };
            }
        }
      }

      const { data: { user } } = await supabase.auth.getUser();

      const updates: Record<string, unknown> = { status: nextStatus };

      // Tracking editorial
      if (nextStatus === 'review' && user) {
        updates.created_by = user.id;
      }
      if (nextStatus === 'approved' && user) {
        updates.reviewed_by = user.id;
        updates.approved_by = user.id;
      }
      if (nextStatus === 'published') {
        updates.published_at = new Date().toISOString();
      }
      if (nextStatus === 'archived') {
        updates.archived_at = new Date().toISOString();
      }

      const { error } = await supabase
        .from('current_topics')
        .update(updates)
        .eq('id', id);

      if (error) throw error;
      return { success: true };
    } catch (e) {
      logger.error(`Error al cambiar estado de tema ${id} a ${nextStatus}`, { error: e });
      return { success: false, error: 'Excepción de base de datos' };
    }
  },

  /**
   * Marcar explícitamente si fue editado por admin
   */
  async markAsAdminEdited(id: string): Promise<boolean> {
    try {
      const { error } = await supabase
        .from('current_topics')
        .update({ admin_edited: true })
        .eq('id', id);

      if (error) throw error;
      return true;
    } catch (e) {
      logger.error(`Error al marcar editado por admin en tema ${id}`, { error: e });
      return false;
    }
  }
};

import { supabase } from "../../../supabase/client";
import { logger } from "../../../lib/logger";

export interface AdminSignalOption {
    id: string;
    label: string;
    image_url: string | null;
}

export interface AdminSignalRow {
    id: string;
    title: string;
    description: string | null;
    status: string;
    created_at: string;
    category_name: string | null;
    total_votes: number;
    options: AdminSignalOption[];
}

export const adminSignalsService = {
    async searchSignals(searchTerm: string = '', statusFilter: string = 'all', limit: number = 50, offset: number = 0): Promise<AdminSignalRow[]> {
        try {
            const { data, error } = await supabase.rpc('admin_search_battles', {
                search_term: searchTerm,
                status_filter: statusFilter,
                limit_count: limit,
                offset_count: offset
            });

            if (error) {
                logger.error("Error searching signals from admin RPC", { domain: 'admin_actions', origin: 'adminSignalsService', action: 'search_signals' }, error);
                throw error;
            }

            return data as unknown as AdminSignalRow[];
        } catch (error) {
            logger.error("Unexpected error searching signals", { domain: 'admin_actions', origin: 'adminSignalsService', action: 'search_signals' }, error);
            return [];
        }
    },

    async updateStatus(battleId: string, newStatus: string): Promise<{ success: boolean; error?: string }> {
        try {
            const { error } = await supabase
                .from('battles')
                .update({ status: newStatus })
                .eq('id', battleId);

            if (error) {
                return { success: false, error: error.message };
            }
            return { success: true };
        } catch (err) {
            return { success: false, error: 'Error inesperado al actualizar estado' };
        }
    }
};

import { supabase } from '../../../supabase/client';
import { logger } from '../../../lib/logger';

export type AdminUserRow = {
    user_id: string;
    nickname: string | null;
    role: string;
    created_at: string;
    total_interactions: number;
    is_identity_verified: boolean;
};

export const adminUsersService = {
    searchUsers: async (searchTerm: string = ''): Promise<AdminUserRow[]> => {
        try {
            const { data, error } = await (supabase.rpc as any)('admin_search_users', { p_search_term: searchTerm });
            if (error) throw error;
            return data as AdminUserRow[];
        } catch (error) {
            logger.error("Error searching users", { domain: 'admin_actions', origin: 'adminUsersService', action: 'search' }, error);
            throw error;
        }
    },

    updateRole: async (userId: string, targetRole: 'user' | 'admin' | 'b2b'): Promise<boolean> => {
        try {
            // Using standard update, assuming RLS allows admin to update users role
            // If not, we would need another RPC.
            const { error } = await supabase.from('users').update({ role: targetRole }).eq('user_id', userId);
            if (error) throw error;
            return true;
        } catch (error) {
            logger.error("Error updating user role", { domain: 'admin_actions', origin: 'adminUsersService', action: 'update_role' }, error);
            throw error;
        }
    }
};

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { authService } from '../services/authService';
import { supabase } from '../../../supabase/client';
import { logger } from '../../../lib/logger';
import { notifyService, formatKnownError } from '../../notifications/notifyService';
import { SEG_AGE_BUCKETS, SEG_REGIONS } from "../../../lib/demographicsNormalize";
import { track } from "../../telemetry/track";

interface OnboardingFlowProps {
    onClose: () => void;
    onSuccess: () => void;
    isMandatory?: boolean;
}

type Step = 'identity' | 'demographics' | 'success';
type Mode = 'register' | 'login';

export default function OnboardingFlow({ onClose, onSuccess, isMandatory = false }: OnboardingFlowProps) {
    const [step, setStep] = useState<Step>('identity');
    const [mode, setMode] = useState<Mode>('register');
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [errorMsg, setErrorMsg] = useState<string>('');
    const [inviteCode, setInviteCode] = useState('');
    const [nickname, setNickname] = useState('');

    // Demographics State
    const [gender, setGender] = useState('');
    const [ageRange, setAgeRange] = useState('');
    const [region, setRegion] = useState('');

    // Recover OAuth bootstrap data on mount
    useState(() => {
        const stored = authService.getStoredOAuthBootstrap();
        if (stored) {
            setNickname(stored.nickname);
            setInviteCode(stored.inviteCode);
            // Si hay datos guardados, es probable que vengamos de un redirect exitoso
            // pero el bootstrap se disparará en el ciclo de vida de AuthContext o aquí si hay sesión activa.
        }
    });

    const handleOAuth = async (provider: 'google' | 'apple') => {
        setLoading(true);
        setErrorMsg('');
        try {
            if (mode === 'register') {
                if (!nickname.trim() || inviteCode.trim().length < 4) {
                    throw new Error("Ingresa tu Alias y Código de invitación antes de continuar.");
                }
                // Persistimos para recuperarlo tras el redirect
                authService.prepareOAuthBootstrap(nickname, inviteCode);
            }

            const { error } = await supabase.auth.signInWithOAuth({
                provider,
                options: {
                    redirectTo: window.location.origin
                }
            });
            if (error) throw error;
            // Si es OAuth, Supabase maneja la redirección.
            // Tras volver, el authService.getEffectiveProfile() detectará la sesión real.
            // Nota: En OAuth el chequeo del código se hará al recargar la app (verificación externa) o mediante un middleware.
        } catch (err: any) {
            logger.error(err);
            const msg = formatKnownError(err) || err.message || 'Error al conectar con el proveedor';
            setErrorMsg(msg);
            notifyService.error(msg);
            setLoading(false);
        }
    };

    const handleEmailAuth = async () => {
        setLoading(true);
        setErrorMsg('');
        try {
            if (mode === 'register') {
                if (!nickname.trim() || inviteCode.trim().length < 4) {
                    throw new Error("Por favor ingresa un código de invitación válido y un nickname.");
                }
                await authService.registerWithEmail(email, password);
            } else {
                await authService.loginWithEmail(email, password);
            }

            // Check Bootstrap status
            const bs = await authService.getBootstrapStatus();

            if (bs.needsBootstrap) {
                if (!nickname.trim() || !inviteCode.trim()) {
                    await authService.signOut();
                    throw new Error('Debes proveer un código de invitación válido para tu primera sesión.');
                }
                try {
                    await authService.bootstrapUserAfterSignup(nickname, inviteCode);
                } catch (bsErr: any) {
                    await authService.signOut();
                    track("auth_bootstrap_failed", "warn", { mode });
                    throw new Error("Código inválido / expirado / ya usado.");
                }
            }

            // Si funciona correctamente, pasamos al step de demográficos
            track("auth_email_success", "info", { mode });
            setStep('demographics');
        } catch (err: any) {
            logger.error(err);
            const msg = formatKnownError(err) || err.message || 'Error en las credenciales';
            setErrorMsg(msg);
            notifyService.error(msg);
        } finally {
            setLoading(false);
        }
    };

    const handleDemographics = async () => {
        setLoading(true);
        try {
            await authService.updateProfileDemographics({
                gender,
                ageBucket: ageRange,
                region,
                profileStage: 1,
                signalWeight: 1.0
            });
            track("profile_stage_1_completed", "info", { source: "onboarding", gender, region, age_bucket: ageRange });
            track("onboarding_completed", "info");
            setStep('success');
        } catch (err: any) {
            logger.error(err);
            const msg = formatKnownError(err) || err.message || 'Error al guardar perfil. Intenta nuevamente.';
            setErrorMsg(msg);
            notifyService.error(msg);
        } finally {
            setLoading(false);
        }
    };

    const variants = {
        enter: (direction: number) => ({
            x: direction > 0 ? 100 : -100,
            opacity: 0
        }),
        center: {
            x: 0,
            opacity: 1
        },
        exit: (direction: number) => ({
            x: direction < 0 ? 100 : -100,
            opacity: 0
        })
    };

    return (
        <div role="dialog" aria-modal="true" aria-labelledby="onboarding-title" className="relative w-full max-w-md bg-white rounded-[32px] shadow-2xl overflow-hidden min-h-[500px] flex flex-col">
            <AnimatePresence mode="wait" custom={step === 'identity' ? -1 : 1}>
                {step === 'identity' && (
                    <motion.div
                        key="identity"
                        custom={1}
                        variants={variants}
                        initial="enter"
                        animate="center"
                        exit="exit"
                        className="p-8 flex-1 flex flex-col"
                    >
                        <div className="text-center mb-8">
                            <div className="w-16 h-16 bg-primary-50 rounded-2xl flex items-center justify-center mx-auto mb-4 text-primary-600">
                                <span className="material-symbols-rounded text-3xl">badge</span>
                            </div>
                            <h2 id="onboarding-title" className="text-2xl font-black text-slate-900 tracking-tight">Elige tu Alias</h2>
                            <p className="text-sm text-slate-500 font-medium mt-2">
                                Tu identidad real siempre será privada. Elige tu alias público.
                            </p>
                        </div>

                        <div className="space-y-3">
                            <button
                                onClick={() => handleOAuth('google')}
                                disabled={loading}
                                className="w-full flex items-center justify-center gap-3 bg-white border border-slate-200 py-3.5 rounded-2xl font-bold text-slate-700 hover:bg-slate-50 transition-all active:scale-[0.98] disabled:opacity-50 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary-500"
                            >
                                <img src="https://www.gstatic.com/firebasejs/ui/2.0.0/images/auth/google.svg" className="w-5 h-5" alt="G" />
                                Continuar con Google
                            </button>
                            <button
                                onClick={() => handleOAuth('apple')}
                                disabled={loading}
                                className="w-full flex items-center justify-center gap-3 bg-black py-3.5 rounded-2xl font-bold text-white hover:opacity-90 transition-all active:scale-[0.98] disabled:opacity-50 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary-500"
                            >
                                <svg className="w-5 h-5 fill-current" viewBox="0 0 24 24"><path d="M17.05 20.28c-.98.95-2.05.8-3.08.35-1.09-.46-2.09-.48-3.24 0-1.44.62-2.2.44-3.06-.35C2.79 15.25 3.51 7.59 9.05 7.31c1.35.07 2.29.74 3.08.74 1.18 0 2.21-.93 3.69-.74 2.4.29 4.1.84 4.87 2.21-.19.04-2.82 1.54-2.79 5.86.06 4.38 3.86 5.84 4.07 5.92-.02.04-.6 1.99-1.39 3.03-.78 1.04-1.61 2.08-3.53 1.95zM12.03 7.25c-.15-2.23 1.66-4.07 3.74-4.25.17 2.25-2.05 4.19-3.74 4.25z" /></svg>
                                Continuar con Apple
                            </button>
                        </div>

                        <div className="my-6 flex items-center gap-4">
                            <div className="h-px flex-1 bg-slate-100" />
                            <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">O usa tu email e ID</span>
                            <div className="h-px flex-1 bg-slate-100" />
                        </div>

                        <div className="mb-4 flex gap-2">
                            <button
                                onClick={() => { setMode('register'); setErrorMsg(''); }}
                                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-1 focus-visible:ring-primary-500 ${mode === 'register' ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
                            >
                                Crear cuenta
                            </button>
                            <button
                                onClick={() => { setMode('login'); setErrorMsg(''); }}
                                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-1 focus-visible:ring-primary-500 ${mode === 'login' ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
                            >
                                Ingresar
                            </button>
                        </div>

                        <div className="space-y-3">
                            {mode === 'register' && (
                                <>
                                    <div>
                                        <label htmlFor="nickname" className="sr-only">Alias</label>
                                        <input
                                            id="nickname"
                                            type="text"
                                            placeholder="Alias"
                                            value={nickname}
                                            onChange={(e) => setNickname(e.target.value)}
                                            className="w-full px-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-primary-500/20"
                                        />
                                        <p className="mt-1 ml-2 text-[10px] text-slate-400 font-medium">Tu identidad real siempre será privada.</p>
                                    </div>
                                    <div>
                                        <label htmlFor="inviteCode" className="sr-only">Código de invitación</label>
                                        <input
                                            id="inviteCode"
                                            type="text"
                                            placeholder="Código de invitación"
                                            value={inviteCode}
                                            onChange={(e) => setInviteCode(e.target.value.toUpperCase())}
                                            className="w-full px-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-bold uppercase tracking-widest focus:outline-none focus:ring-2 focus:ring-primary-500/20"
                                        />
                                    </div>
                                </>
                            )}
                            <div>
                                <label htmlFor="email" className="sr-only">Correo electrónico (tu@email.com)</label>
                                <input
                                    id="email"
                                    type="email"
                                    placeholder="tu@email.com"
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    className="w-full px-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-primary-500/20"
                                />
                            </div>
                            <div>
                                <label htmlFor="password" className="sr-only">Crea una contraseña segura</label>
                                <input
                                    id="password"
                                    type="password"
                                    placeholder="Crea una contraseña segura"
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="w-full px-4 py-3.5 bg-slate-50 border border-slate-100 rounded-2xl text-sm font-medium focus:outline-none focus:ring-2 focus:ring-primary-500/20"
                                />
                            </div>

                            {errorMsg && (
                                <div role="alert" aria-live="polite">
                                    <p className="text-xs text-red-500 font-bold mb-2 text-center">{errorMsg}</p>
                                </div>
                            )}

                            <button
                                onClick={handleEmailAuth}
                                disabled={!email || !password || (mode === 'register' && (!nickname || !inviteCode)) || loading}
                                className="w-full bg-primary-600 py-3.5 rounded-2xl font-black text-white shadow-lg shadow-primary-200 transition-all active:scale-[0.98] disabled:opacity-50 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary-500"
                            >
                                {loading ? 'Cargando...' : (mode === 'register' ? 'Registrarme' : 'Entrar')}
                            </button>
                        </div>
                    </motion.div>
                )}

                {step === 'demographics' && (
                    <motion.div
                        key="demographics"
                        custom={1}
                        variants={variants}
                        initial="enter"
                        animate="center"
                        exit="exit"
                        className="p-8 flex-1 flex flex-col"
                    >
                        <div className="text-center mb-8">
                            <div className="w-16 h-16 bg-blue-50 rounded-2xl flex items-center justify-center mx-auto mb-4 text-blue-600">
                                <span className="material-symbols-rounded text-3xl">diversity_3</span>
                            </div>
                            <h2 id="onboarding-title" className="text-2xl font-black text-slate-900 tracking-tight">Tu Perfil</h2>
                            <p className="text-sm text-slate-500 font-medium mt-2">
                                Esto nos permite ponderar tu opinión según representatividad.
                            </p>
                        </div>

                        {errorMsg && (
                            <div role="alert" aria-live="polite">
                                <p className="text-xs text-red-500 font-bold mb-4 text-center">{errorMsg}</p>
                            </div>
                        )}

                        <div className="space-y-5">
                            <div>
                                <div id="gender-label" className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Género</div>
                                <p className="text-[11px] text-slate-400 mb-2 font-medium">Requerido para el análisis colaborativo.</p>
                                <div className="grid grid-cols-3 gap-2">
                                    {[
                                        { id: "male", label: "Hombre" },
                                        { id: "female", label: "Mujer" },
                                        { id: "other", label: "Otro" },
                                    ].map(g => (
                                        <button
                                            key={g.id}
                                            aria-labelledby="gender-label"
                                            onClick={() => setGender(g.id)}
                                            className={`py-2.5 rounded-xl text-xs font-bold border transition-all focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-1 focus-visible:ring-primary-500 ${gender === g.id ? 'bg-primary-600 border-primary-600 text-white' : 'bg-white border-slate-100 text-slate-500 hover:border-primary-200'
                                                }`}
                                        >
                                            {g.label}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label htmlFor="ageRange" className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">Edad</label>
                                <p className="text-[11px] text-slate-400 mb-2 font-medium">Para descubrir las tendencias por generación.</p>
                                <select
                                    id="ageRange"
                                    value={ageRange}
                                    onChange={(e) => setAgeRange(e.target.value)}
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold text-slate-600 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary-500"
                                >
                                    <option value="">Selecciona…</option>
                                    {SEG_AGE_BUCKETS.filter(a => a.value !== "all").map(a => (
                                        <option key={a.value} value={a.value}>{a.label}</option>
                                    ))}
                                </select>
                            </div>

                            <div>
                                <label htmlFor="region" className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 block">¿Dónde estás?</label>
                                <p className="text-[11px] text-slate-400 mb-2 font-medium">Para detectar tendencias en tu región.</p>
                                <select
                                    id="region"
                                    value={region}
                                    onChange={(e) => setRegion(e.target.value)}
                                    className="w-full px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl text-xs font-bold text-slate-600 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary-500"
                                >
                                    <option value="">Selecciona…</option>
                                    {SEG_REGIONS.filter(r => r.value !== "all").map(r => (
                                        <option key={r.value} value={r.value}>{r.label}</option>
                                    ))}
                                </select>
                            </div>

                            <button
                                onClick={handleDemographics}
                                disabled={!gender || !ageRange || !region || loading}
                                className="w-full bg-slate-900 py-4 rounded-2xl font-black text-white shadow-xl transition-all active:scale-[0.98] disabled:opacity-30 mt-4 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary-500"
                            >
                                {loading ? 'Un segundo…' : 'Listo'}
                            </button>
                        </div>
                    </motion.div>
                )}

                {step === 'success' && (
                    <motion.div
                        key="success"
                        custom={1}
                        variants={variants}
                        initial="enter"
                        animate="center"
                        exit="exit"
                        className="p-8 flex-1 flex flex-col items-center justify-center text-center"
                    >
                        <div className="w-20 h-20 bg-emerald-50 rounded-3xl flex items-center justify-center mb-6 text-emerald-500">
                            <motion.span
                                initial={{ scale: 0.5, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1 }}
                                transition={{ type: 'spring', damping: 12 }}
                                className="material-symbols-rounded text-5xl"
                            >
                                check_circle
                            </motion.span>
                        </div>
                        <h2 id="onboarding-title" className="text-3xl font-black text-slate-900 tracking-tighter">Listo. Ya puedes dejar tus señales.</h2>
                        <p className="text-slate-500 font-medium mt-3 leading-relaxed">
                            Tu cuenta ha sido configurada y está lista para impactar las tendencias. (Desbloqueaste <span className="text-primary-600 font-bold text-sm">15 señales</span>).
                        </p>

                        <div className="grid grid-cols-2 gap-3 w-full mt-10">
                            <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                                <div className="text-primary-600 font-black text-xl mb-1">15</div>
                                <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Señales/Día</div>
                            </div>
                            <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                                <div className="text-primary-600 font-black text-xl mb-1">ON</div>
                                <div className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Insights</div>
                            </div>
                        </div>

                        <button
                            onClick={onSuccess}
                            className="w-full bg-primary-600 py-4 rounded-2xl font-black text-white shadow-lg shadow-primary-200 transition-all active:scale-[0.98] mt-8 focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary-500"
                        >
                            Ir a Señales →
                        </button>
                    </motion.div>
                )}
            </AnimatePresence>

            {(!isMandatory || step === 'success') && (
                <div className="p-4 bg-slate-50 flex items-center justify-center">
                    <button
                        onClick={onClose}
                        className="text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-slate-600 transition-colors focus:outline-none focus-visible:ring-2 focus-visible:ring-offset-2 focus-visible:ring-primary-500 p-2 rounded-lg"
                    >
                        Cerrar
                    </button>
                </div>
            )}
        </div>
    );
}

