            } else if (step === 1 && errMsg.includes("INVITE")) {
                showToast("Código inválido / expirado / ya usado. Vuelve a /access e ingresa otro.", "error");
            } else {
                showToast(errMsg || "Ocurrió un error al guardar tu perfil. Intenta nuevamente.", "error");
