import { useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { MODULES, OpinaModule } from "../modulesConfig";
import PageHeader from "../../../components/ui/PageHeader";

// Preview Templates
import PreviewShell from "../../modulesPreviews/PreviewShell";
import PreviewFilterBar from "../../modulesPreviews/PreviewFilterBar";
import PreviewList from "../../modulesPreviews/PreviewList";
import PreviewDetailDrawer from "../../modulesPreviews/PreviewDetailDrawer";
import PreviewContextCheck from "../../modulesPreviews/PreviewContextCheck";
import PreviewNewsCard from "../../modulesPreviews/PreviewNewsCard";
import PreviewProductSheet from "../../modulesPreviews/PreviewProductSheet";
import PreviewNpsSurvey from "../../modulesPreviews/PreviewNpsSurvey";
import { rateLimit } from '../../../shared/utils/rateLimit';
import { moduleInterestService } from "../../modulesPreviews/moduleInterestService";
import { MODULE_EVENT_TYPES } from "../../signals/eventTypes";

export default function ComingSoonModule({ module }: { module?: OpinaModule }) {
    const nav = useNavigate();
    const { slug } = useParams();

    const activeModule = module || MODULES.find((m) => m.slug === slug);

    useEffect(() => {
        window.scrollTo(0, 0);

        // Track module preview viewed signal
        if (activeModule && activeModule.status === 'soon') {
            const limitKey = `opina_module_viewed:${activeModule.slug}:daily:`;
            if (!rateLimit.hasSent(limitKey)) {
                moduleInterestService.trackModuleInterestEvent(MODULE_EVENT_TYPES.MODULE_PREVIEW_VIEWED, {
                    module_key: activeModule.title, // Fallback to title if id is not on interface
                    module_slug: activeModule.slug,
                    // @ts-expect-error - type no definido estáticamente temporalmente
                    previewType: activeModule.previewType || 'unknown',
                    source: "coming_soon",
                    entry: "hub_card"
                });
                rateLimit.markSent(limitKey);
            }
        }
    }, [activeModule]);

    if (!activeModule) {
        return (
            <div className="flex items-center justify-center min-h-[50vh] text-slate-500 font-bold">
                Módulo no encontrado.
            </div>
        );
    }

    const renderPreviewContent = () => {
        // @ts-expect-error - falta el tipado correspondiente en previewType
        const type = activeModule.previewType;
        // @ts-expect-error - falta el tipado correspondiente en previewData
        const data = activeModule.previewData as any;

        switch (type) {
            case "context_check":
                return <PreviewContextCheck checkins={data.checkins} />;

            case "lugares":
            case "servicios":
                return (
                    <div className="flex gap-8">
                        <div className="flex-1">
                            <PreviewFilterBar
                                categories={data.categories}
                                communes={data.communes}
                                placeholder={`Buscar ${activeModule.title.toLowerCase()}...`}
                            />
                            <PreviewList
                                items={data.items}
                                renderItem={(item, i) => (
                                    <div key={i} className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm opacity-60">
                                        <div className="w-full h-32 bg-slate-100 rounded-2xl mb-4 flex items-center justify-center text-slate-300">
                                            <span className="material-symbols-outlined text-4xl">
                                                {activeModule.icon}
                                            </span>
                                        </div>
                                        <h4 className="text-sm font-black text-slate-800 mb-1">{item.name}</h4>
                                        <div className="flex justify-between items-center text-[10px] font-bold text-slate-400">
                                            <span>{item.category}</span>
                                            <span className="flex items-center gap-1 text-blue-600">
                                                <span className="material-symbols-outlined text-[14px]">star</span>
                                                {item.rating}
                                            </span>
                                        </div>
                                    </div>
                                )}
                            />
                        </div>
                        <PreviewDetailDrawer
                            isOpen={true}
                            title={data.items[0].name}
                            category={data.items[0].category}
                            rating={data.items[0].rating}
                        />
                    </div>
                );

            case "news_opinion":
                return (
                    <div className="max-w-3xl mx-auto">
                        <PreviewFilterBar categories={["Política", "Economía", "Social", "Tecnología"]} />
                        <PreviewNewsCard items={data.news} />
                    </div>
                );

            case "productos":
                return <PreviewProductSheet product={data.product} />;

            case "nps_survey":
                return <PreviewNpsSurvey question={data.nps_question} followUps={data.follow_ups} />;

            default:
                return (
                    <div className="py-20 text-center opacity-20 grayscale">
                        <span className="material-symbols-outlined text-6xl mb-4">construction</span>
                        <p className="font-black uppercase tracking-widest text-xs">Módulo en Construcción</p>
                    </div>
                );
        }
    };

    return (
        <div className="min-h-screen bg-slate-50 pb-20">
            <PageHeader
                title={activeModule.title}
                subtitle="Preview de Funcionalidad"
            />

            <PreviewShell
                title={activeModule.mockTitle || `El futuro de ${activeModule.title}`}
                description={activeModule.mockSubtitle || activeModule.description}
                icon={activeModule.icon}
                tone={activeModule.tone}
                bullets={activeModule.mockBullets || []}
                onBack={() => nav(-1)}
                onRequestLaunch={() => {
                    // Acción visual para el usuario
                    alert("¡Gracias por tu interés! Hemos registrado tu solicitud para priorizar este lanzamiento.");
                }}
            >
                {renderPreviewContent()}
            </PreviewShell>
        </div>
    );
}

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useActiveBattles } from "../../../hooks/useActiveBattles";
import { useSignalStore } from "../../../store/signalStore";
import { useAuth } from "../../auth";

import PageHeader from "../../../components/ui/PageHeader";
import { PageState } from "../../../components/ui/StateBlocks";
import { SkeletonModuleCard } from "../../../components/ui/Skeleton";

import HubMenuSimplified from "../components/HubMenuSimplified";
import { ActualidadHubManager } from "../components/ActualidadHubManager";

import VersusView from "../components/VersusView";
import TorneoView from "../components/TorneoView";
import ProfundidadView from "../components/ProfundidadView";
import BatchSessionResults, { BatchSessionResultRecord } from "../components/BatchSessionResults";

import { useExperienceMode, useExperienceStats } from "../hooks/useExperienceMode";
import { Battle } from "../../signals/types";

const BATCH_SIZE = 12;

export default function SignalsHub() {
    const { mode, setMode, requestedBatch, resetToMenu } = useExperienceMode();
    const { hubStats, hubTopNow } = useExperienceStats();

    const { battles, loading } = useActiveBattles();
    const { profile } = useAuth();
    const { signals, signalsToday } = useSignalStore();
    const navigate = useNavigate();

    const [showBatchResults, setShowBatchResults] = useState(false);
    const [batchSessionHistory, setBatchSessionHistory] = useState<BatchSessionResultRecord[]>([]);

    const computedBatch = Math.floor(signals / BATCH_SIZE);
    const initialBatch = typeof requestedBatch === "number" ? requestedBatch : computedBatch;
    const [batchIndex] = useState(initialBatch);

    const fmt = (n: number) => new Intl.NumberFormat("es-CL").format(Number.isFinite(n) ? n : 0);
    const signalsLimit = profile?.role === 'admin' ? '∞' : profile?.signalsDailyLimit === -1 ? '∞' : (profile?.signalsDailyLimit ?? "?").toString();

    useEffect(() => {
        if (profile && !profile.isProfileComplete && profile.role !== 'admin') {
            navigate("/complete-profile", { replace: true });
        }
    }, [profile, navigate]);

    if (profile && !profile.isProfileComplete && profile.role !== 'admin') return null;

    const handleBatchComplete = (history: BatchSessionResultRecord[]) => {
        setBatchSessionHistory(history || []);
        setShowBatchResults(true);
    };

    const headerSubtitle = mode === "menu"
        ? "Elige tu canal. Rápido, anónimo y sin discursos innecesarios."
        : mode === "versus"
            ? `Bloque ${batchIndex + 1}: calibrando preferencias.`
            : mode === "torneo"
                ? "Modo torneo: una opción sobrevive y sigue peleando."
                : "Profundidad: 5 preguntas rápidas para afinar el motor.";

    if (loading && battles.length === 0) {
        return (
            <div className="container-ws section-y space-y-6 pb-24">
                <PageHeader
                    eyebrow={<span className="badge badge-primary">Hub</span>}
                    title={<h1 className="text-2xl md:text-3xl font-black tracking-tight text-ink">Elige tu <span className="text-primary">formato</span></h1>}
                    subtitle={<p className="text-sm text-muted font-medium">{headerSubtitle}</p>}
                    meta={
                        <div className="flex flex-wrap gap-2">
                            <div className="badge badge-outline">Señales hoy: {fmt(signalsToday)}</div>
                            <div className="badge badge-outline">Límite: {signalsLimit}</div>
                        </div>
                    }
                />
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 opacity-80">
                    <SkeletonModuleCard />
                    <SkeletonModuleCard />
                    <SkeletonModuleCard />
                </div>
            </div>
        );
    }

    if (!loading && battles.length === 0) {
        return (
            <div className="container-ws section-y">
                <PageState
                    type="empty"
                    title="No hay evaluaciones activas"
                    description="Estamos recargando el motor de señales."
                    icon="dns"
                    primaryAction={{ label: "Volver al inicio", onClick: () => navigate("/") }}
                />
            </div>
        );
    }

    return (
        <div className={`container-ws pb-24 ${mode === 'menu' ? 'section-y space-y-8' : 'pt-4 md:pt-8 space-y-6'}`}>

            {mode === "menu" && (
                <HubMenuSimplified
                    onEnterVersus={() => setMode('versus')}
                    onEnterTorneo={() => setMode("torneo")}
                    onEnterProfundidad={() => setMode("profundidad")}
                    onEnterActualidad={() => setMode("actualidad")}
                    onViewResults={() => navigate("/results")}
                    stats={hubStats}
                    topNow={hubTopNow}
                    previewVersus={battles.length > 0 ? (battles[0] as any) : null}
                    signalsToday={signalsToday}
                    signalsLimit={signalsLimit === '∞' ? '∞' : Number(signalsLimit)}
                />
            )}

            {mode !== "menu" && mode !== "actualidad" && (
                <div className="w-full flex justify-start animate-in fade-in duration-300">
                    <button
                        onClick={resetToMenu}
                        className="h-10 px-4 rounded-xl bg-white border border-slate-200 hover:bg-slate-50 hover:border-slate-300 text-slate-600 hover:text-slate-900 font-bold text-sm transition-all shadow-sm active:scale-95 shrink-0 flex items-center gap-2"
                    >
                        <span className="material-symbols-outlined text-[16px]">arrow_back</span>
                        Volver a Señales
                    </button>
                </div>
            )}

            {mode === "versus" && (
                <VersusView 
                    battles={(battles as unknown as Battle[])} 
                    batchIndex={batchIndex} 
                    onBatchComplete={handleBatchComplete} 
                />
            )}

            {mode === "torneo" && <TorneoView battles={(battles as unknown as Battle[])} />}

            {mode === "profundidad" && <ProfundidadView battles={(battles as unknown as Battle[])} onClose={resetToMenu} />}

            {mode === "actualidad" && (
                <div className="space-y-8 animate-in fade-in duration-500">
                    <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm p-4 md:p-8 min-h-[600px] relative overflow-hidden">
                        <ActualidadHubManager onClose={resetToMenu} />
                    </div>
                </div>
            )}

            <BatchSessionResults 
                showBatchResults={showBatchResults}
                batchSessionHistory={batchSessionHistory}
                batchIndex={batchIndex}
                onClose={() => setShowBatchResults(false)}
            />
        </div>
    );
}

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../../auth/hooks/useAuth';
import { supabase } from '../../../supabase/client';
import {
  getUserLoyaltyStats,
  getUserWallet,
  getWeeklyMissionsProgress,
  UserLoyaltyStats,
  UserWallet,
} from '../services/loyaltyService';

export function useLoyalty() {
  const { profile } = useAuth();

  const [stats, setStats] = useState<UserLoyaltyStats | null>(null);
  const [wallet, setWallet] = useState<UserWallet | null>(null);
  const [missions, setMissions] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchLoyaltyData = useCallback(async () => {
    // Relying on useAuth's profile to know if lightly authenticated
    if (!profile) {
      setStats(null);
      setWallet(null);
      setMissions([]);
      setIsLoading(false);
      return;
    }

    try {
      setIsLoading(true);
      setError(null);

      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("No user found");

      const [statsData, walletData, missionsData] = await Promise.all([
        getUserLoyaltyStats(user.id),
        getUserWallet(user.id),
        getWeeklyMissionsProgress(user.id),
      ]);

      setStats(statsData);
      setWallet(walletData);
      setMissions(missionsData);
    } catch (err) {
      console.error('Failed to load loyalty data:', err);
      setError('Error al cargar la información de recompensas.');
    } finally {
      setIsLoading(false);
    }
  }, [profile]);

  useEffect(() => {
    fetchLoyaltyData();
  }, [fetchLoyaltyData]);

  return {
    stats,
    wallet,
    missions,
    isLoading,
    error,
    refreshLoyaltyData: fetchLoyaltyData,
  };
}

